-- ============================================================================
-- 020: Backfill real bilingual instructions + kosher type
-- ============================================================================
-- Matches existing recipes by name (already imported by strauss_recipes_
-- import.sql) and fills in the columns 019 just added. Run AFTER both 019
-- and the recipe import.

update public.recipes set instructions_en = 'In a shallow baking dish, combine the flour, salt, pepper, onion powder, and garlic powder. Dredge the chicken in the flour mixture just to coat lightly. Shake off excess coating. | In a large skillet with 3-inch sides, heat 3 tablespoons of the olive oil and the margarine over high heat. Working in batches, brown the chicken on both sides, about 3 minutes per side. Remove chicken from skillet and set aside. | In the same large skillet, heat the remaining 2 tablespoons of olive oil over medium heat. Add the red pepper, yellow pepper, and red onions, and cook for 7 minutes. Add the garlic and stir until softened, about 1 minute. | In a small bowl, whisk the balsamic vinegar, soy sauce, brown sugar, salt, and pepper. Add the mixture to the vegetables and stir until it becomes a sauce. Continue cooking until the vegetables are soft and the balsamic sauce has reduced to a syrup, about 4 more minutes. Place the chicken back in the pan and coat with the sauce. Simmer until the chicken is cooked through, about 4 minutes. | Serve chicken topped with the onions and peppers and drizzled with the sauce. Garnish with fresh basil if desired.', instructions_es = 'En una fuente poco profunda, mezcla la harina, la sal, la pimienta, la cebolla en polvo y el ajo en polvo. Pasa el pollo por esta mezcla apenas para cubrirlo y sacude el exceso. | En una sartén grande con bordes altos, calienta 3 cucharadas del aceite de oliva junto con la margarina a fuego alto. Dora el pollo en tandas, aproximadamente 3 minutos por lado. Retíralo y resérvalo. | En la misma sartén, calienta las 2 cucharadas restantes de aceite de oliva a fuego medio. Agrega los pimientos y las cebollas y cocina 7 minutos. Agrega el ajo y cocina aproximadamente 1 minuto más, hasta que se ablande. | En un bowl pequeño, bate el vinagre balsámico, la salsa de soja, el azúcar morena, la sal y la pimienta. Agrégalo a las verduras y cocina hasta que se convierta en una salsa espesa, unos 4 minutos más. | Vuelve a poner el pollo en la sartén y mézclalo con la salsa. Cocina a fuego bajo hasta que el pollo esté bien cocido, unos 4 minutos. | Sirve el pollo cubierto con las cebollas, los pimientos y la salsa. Decora con albahaca fresca si deseas.', kosher_type = 'Meat' where name = 'Balsamic Chicken with Peppers & Onions' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine all ingredients. | Pour over steaks or cutlets. | Let marinate for at least 1 hour to tenderize. | Grill and enjoy.', instructions_es = 'Mezcla todos los ingredientes. | Viértela sobre steaks o cutlets. | Déjala marinar por lo menos 1 hora para ablandar la carne. | Asa o cocina a la parrilla y sirve.', kosher_type = 'Parve' where name = 'Go-To Marinade' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a large nonstick frying pan with a lid, saute onion in oil until beginning to brown. | Add mushrooms and continue to saute until softened. Push vegetables to one side of the pan. | Add chicken in a single layer and sear on both sides. | Add remaining ingredients to the pan and bring to a boil. | Lower heat and simmer, covered, for 15 minutes, or until quinoa is cooked through. | Serve hot.', instructions_es = 'En una sartén grande antiadherente con tapa, saltea la cebolla en aceite hasta que empiece a dorarse. | Agrega los hongos y sigue salteando hasta que se ablanden. Lleva las verduras a un lado de la sartén. | Agrega el pollo en una sola capa y dóralo por ambos lados. | Añade el resto de los ingredientes y lleva a hervor. | Baja el fuego, tapa y cocina durante 15 minutos, o hasta que la quinoa esté cocida. | Sirve caliente.', kosher_type = 'Meat' where name = 'Teriyaki Quinoa Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Dip the chicken into flour, then eggs, then crushed Frosted Flakes. | Fry until cooked through and crisp. | For the sauce, combine the brown sugar and hot sauce or buffalo sauce and bring to a boil. | If the sauce gets too thick, add a little water. | Season the eggs only with garlic powder, salt, and paprika. | Notes | The original source did not include exact chicken quantity or exact seasoning amounts.', instructions_es = 'Pasa el pollo por harina, luego por huevo y después por los Frosted Flakes triturados. | Fríelo hasta que esté bien cocido y crocante. | Para la salsa, mezcla el azúcar morena con la salsa picante o buffalo y llévalo a hervor. | Si la salsa se espesa demasiado, agrega un poco de agua. | Condimenta los huevos solo con ajo en polvo, sal y pimentón. | Nota | La receta original no daba cantidad exacta de pollo ni medidas exactas de condimentos.', kosher_type = 'Meat' where name = 'Frosted Flake Chicken Nuggets with Popper Sauce' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. Grease a roasting pan. | Place chicken into prepared pan. Season chicken lightly with spices. Spread mayonnaise over chicken. Sprinkle with cornflake crumbs to evenly cover. | Cover and bake on the center rack for 1 hour 20 minutes. | Meanwhile, prepare the sweet and tangy sauce: in a small bowl, combine sauce ingredients. | Remove pan from oven. Pour accumulated liquid into a small bowl. Allow liquid to cool, then discard it. | Pour sauce over chicken. Return pan to oven and bake uncovered for 20-30 minutes, until tender. | Notes | You can also use chicken bottoms that were separated into drumsticks and thighs.', instructions_es = 'Precalienta el horno a 350°F y engrasa una fuente para horno. | Coloca el pollo en la fuente preparada. Condiméntalo ligeramente con las especias. | Unta la mayonesa sobre el pollo y espolvorea las migas de cornflakes por encima de manera uniforme. | Tapa y hornea en la rejilla del medio durante 1 hora y 20 minutos. | Mientras tanto, prepara la salsa mezclando todos los ingredientes en un bowl pequeño. | Retira la fuente del horno. Pasa el líquido acumulado a un bowl pequeño, déjalo enfriar y deséchalo. | Vierte la salsa sobre el pollo y vuelve a hornear destapado de 20 a 30 minutos, hasta que esté tierno. | Nota | También puede hacerse con piezas separadas en muslos y patas.', kosher_type = 'Meat' where name = 'Eileen''s Sweet and Tangy Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Season the chicken with 1/2 teaspoon salt and 1/4 teaspoon pepper. Heat the oil in a large skillet over medium-high heat. | Working in 2 batches, cook the chicken until browned and cooked through, 2 to 3 minutes per side. Transfer to plates. | Add the tomatoes to the skillet and cook over medium-high heat, stirring occasionally, until they begin to burst, 2 to 3 minutes. | Add the wine and simmer until the liquid is reduced by half, 2 to 3 minutes. | Stir in the scallions and tarragon and serve with the chicken.', instructions_es = 'Sazona el pollo con 1/2 cucharadita de sal y 1/4 cucharadita de pimienta. Calienta el aceite en una sartén grande a fuego medio-alto. | Cocina el pollo en 2 tandas hasta que se dore y esté bien cocido, de 2 a 3 minutos por lado. Retíralo a platos. | Agrega los tomates a la sartén y cocina a fuego medio-alto, revolviendo de vez en cuando, hasta que empiecen a abrirse, de 2 a 3 minutos. | Agrega el vino y deja hervir suavemente hasta que el líquido se reduzca a la mitad, de 2 a 3 minutos. | Agrega los cebollines y el estragón y sirve junto con el pollo.', kosher_type = 'Meat' where name = 'Chicken Cutlets With Tomato Saute' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 425°F. | Coat a parchment-lined cookie sheet with cooking spray. | Combine flour with garlic powder, salt, and pepper in a shallow dish. | Beat the egg together with the soy sauce in a second dish. Place the cooked quinoa in a third dish. | Dredge the chicken in the flour mixture. Dip in the egg mixture, then dredge in the quinoa. | Arrange chicken in a single layer on the prepared pan. Coat chicken with cooking spray. | Bake at 425°F for 15 minutes or until done, turning once. | Combine mayonnaise and mustard in a small dish and serve with the nuggets.', instructions_es = 'Precalienta el horno a 425°F. | Rocía con spray una bandeja forrada con papel pergamino. | Mezcla la harina con el ajo en polvo, la sal y la pimienta en un plato hondo. | Bate el huevo con la salsa de soja en un segundo plato. Coloca la quinoa cocida en un tercer plato. | Pasa el pollo por la mezcla de harina, luego por el huevo y después por la quinoa. | Acomoda el pollo en una sola capa sobre la bandeja preparada. Rocía con spray. | Hornea a 425°F durante 15 minutos o hasta que esté listo, dándolo vuelta una vez. | Mezcla la mayonesa con la mostaza en un bowl pequeño y sirve con los nuggets.', kosher_type = 'Meat' where name = 'Quinoa Crusted Chicken Nuggets' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Put all of the sauce ingredients into a large pot and turn it on a medium-low flame. | Mix the meat with the teriyaki sauce, garlic powder, and salt, then form small meatballs. | Drop the meatballs one by one into the sauce; you should get about 50 meatballs. | Keep on a medium-low flame, covered, for about 1 1/2 to 2 hours, stirring occasionally. Alternatively, place into a tin pan and bake in the oven.', instructions_es = 'Coloca todos los ingredientes de la salsa en una olla grande y enciende a fuego medio-bajo. | Mezcla la carne con la salsa teriyaki, el ajo en polvo y la sal, y forma albóndigas pequeñas. | Ve dejando las albóndigas una por una dentro de la salsa; deben salir unas 50 albóndigas. | Cocina tapado a fuego medio-bajo durante 1 1/2 a 2 horas, revolviendo de vez en cuando. | También puedes pasarlas a una bandeja descartable y hornearlas.', kosher_type = 'Meat' where name = 'Meatballs' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to broil. | Drizzle olive oil into a 9 x 13-inch baking pan. Lay vegetables flat to cover the bottom of the pan. | Place salmon slices on top of vegetables. Coat salmon and vegetables with nonstick cooking spray; sprinkle with Montreal steak seasoning. | Broil for 12-15 minutes, until fish flakes easily with a fork.', instructions_es = 'Precalienta el horno en función grill. | Rocía aceite de oliva en una fuente de 9 x 13 pulgadas. Acomoda las verduras cubriendo el fondo. | Coloca las porciones de salmón encima de las verduras. | Rocía el salmón y las verduras con spray antiadherente y espolvorea con condimento Montreal steak. | Gratina de 12 a 15 minutos, hasta que el pescado se deshaga fácilmente con un tenedor.', kosher_type = 'Parve' where name = 'Montreal Salmon & Veggies' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F (175°C). Place onion slices on the bottom of a 9 x 13-inch (20 x 30 cm) baking pan. Add chicken pieces on top. | Mix together the rest of the ingredients in a small bowl, forming a paste. Smear all over chicken. | Cover with aluminum foil. Bake for 1 1/2 hours covered and 1/2 hour uncovered. After chicken is uncovered, baste once or twice in the middle. | Notes | For even more flavorful chicken, prepare it Thursday night, let it marinate in the fridge overnight, and bake the next morning.', instructions_es = 'Precalienta el horno a 350°F (175°C). Coloca las rodajas de cebolla en el fondo de una fuente de 9 x 13 pulgadas y acomoda el pollo encima. | Mezcla el resto de los ingredientes en un bowl pequeño hasta formar una pasta. | Unta esta mezcla sobre todo el pollo. | Cubre con papel aluminio y hornea 1 1/2 horas tapado y 1/2 hora destapado. | Después de destaparlo, báñalo con sus jugos una o dos veces durante la cocción. | Nota | Para más sabor, puede prepararse la noche anterior y dejarse marinar en la heladera.', kosher_type = 'Meat' where name = 'Really Good Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a 9 x 13 pan, combine the rice, water, and onion soup mix. Stir. | Top with 4 pieces of chicken, on the bone, with the skin on. | Mix the sauce ingredients and paint the chicken with the sauce. | Sprinkle sesame seeds on top if desired. | Cover tightly with a 9 x 13 lid or tin foil. | Bake for 3 hours at 350°F.', instructions_es = 'En una fuente de 9 x 13 pulgadas, mezcla el arroz, el agua y la mezcla de sopa de cebolla. | Coloca encima las 4 piezas de pollo con hueso y piel. | Mezcla los ingredientes de la salsa y pinta el pollo con ella. | Espolvorea semillas de sésamo si deseas. | Cubre bien con tapa o aluminio y hornea 3 horas a 350°F.', kosher_type = 'Meat' where name = 'One-Pan Chicken and Rice' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. | Add the pasta in an even layer to a 9 x 13-inch baking pan. | Add salt and sauce. Fill the jar with water, either 3/4 full to completely full, and add to the pan. | Add most of the cheese and mix to combine. Add more cheese on top, or mix all of it in. | Cover and bake for 90 minutes. | If you like it crisp, uncover and bake a little longer so the top browns, bubbles, and the noodles crisp up a bit.', instructions_es = 'Precalienta el horno a 350°F. | Coloca la pasta en una capa uniforme dentro de la fuente. | Agrega la sal y la salsa. | Llena el frasco vacío con agua, entre 3/4 y completo, y agrégala a la fuente. | Incorpora la mayor parte del queso y mezcla. Agrega más queso por encima, o usa todo dentro. | Cubre y hornea 90 minutos. | Si te gusta más crocante, destapa y hornea un poco más hasta que la parte de arriba se dore y burbujee.', kosher_type = 'Dairy' where name = 'No Pot Creamy Ziti' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Saute onion and peppers in oil for 20 minutes. | Mix ground meat with oregano, paprika, salt, pepper, garlic powder, onion powder, a pinch of chili flakes, and dried parsley. | Form mini meatballs and drop into the pan. | Cover and cook for 25 minutes. | Add some diced tomatoes if you want. | Serve over pasta or rice. | Notes | Exact quantities were not provided in the source.', instructions_es = 'Saltea la cebolla y los pimientos en aceite durante 20 minutos. | Mezcla la carne picada con el orégano, el pimentón, la sal, la pimienta, el ajo en polvo, la cebolla en polvo, una pizca de chili flakes y perejil seco. | Forma mini albóndigas y colócalas dentro de la sartén. | Tapa y cocina durante 25 minutos. | Si quieres, agrega algunos tomates en cubitos. | Sirve sobre pasta o arroz. | Nota | La receta original no daba cantidades exactas.', kosher_type = 'Meat' where name = 'Italian Mini Meatballs & Peppers' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Bake at 275°F for 2.5 to 3 hours. | Notes | The attachment only showed a very short handwritten note and did not include additional ingredients or directions.', instructions_es = 'Hornea a 275°F durante 2 1/2 a 3 horas. | Nota | La tarjeta original solo mostraba una nota manuscrita muy breve y no incluía más ingredientes ni instrucciones.', kosher_type = 'Parve' where name = 'Sandwich Steaks' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Put the chicken in a bag with the flour and shake. | Make a sauce with the soy sauce, oil, salt, black pepper, garlic, and brown sugar. | Pour the sauce over the chicken in a pan. | Bake 1 hour covered. | Add scallions and snap peas and bake another 15 minutes uncovered.', instructions_es = 'Coloca el pollo en una bolsa con la harina y agita bien. | Prepara una salsa con la salsa de soja, el aceite, la sal, la pimienta negra, el ajo y el azúcar morena. | Vierte la salsa sobre el pollo en una fuente. | Hornea 1 hora tapado. | Agrega los cebollines y los snap peas y hornea 15 minutos más destapado.', kosher_type = 'Meat' where name = 'Chicken with Snap Peas' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix the oil with the cornflake crumbs and spices until the crumbs are very wet. | Coat the cutlets in the mixture. | Bake at 400°F (200°C) for 15 minutes. | Serve with couscous.', instructions_es = 'Mezcla el aceite con las migas de cornflakes y las especias hasta que las migas queden bien húmedas. | Cubre los cutlets con esta mezcla. | Hornea a 400°F (200°C) durante 15 minutos. | Sirve con couscous.', kosher_type = 'Meat' where name = 'Oven-Baked Schnitzel' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté the diced onion and mushrooms and put them in a Crock-Pot. | Lay the chicken on the bone on top. | Cover the chicken with tomato sauce, some water, a little tomato paste, and Italian seasoning. | Cook until done. | Serve with mashed potatoes.', instructions_es = 'Saltea la cebolla y los hongos y colócalos dentro del Crock-Pot. | Acomoda encima el pollo con hueso. | Cubre el pollo con salsa de tomate, un poco de agua, un poco de pasta de tomate y condimento italiano. | Cocina hasta que esté listo. | Sirve con puré de papas.', kosher_type = 'Meat' where name = 'Crock-Pot Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté the onions and peppers. | Add the chicken strips and cook. | Add the fajita spice. | Serve in tortillas, wraps, pitas, or laffa.', instructions_es = 'Saltea las cebollas y los pimientos. | Agrega las tiritas de pollo y cocina. | Agrega el condimento fajita. | Sirve en tortillas, wraps, pitas o laffa.', kosher_type = 'Meat' where name = 'Mexican Chicken Strips' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place the chicken cutlets in a Crock-Pot with the barbecue sauce, ketchup, brown sugar, apple cider vinegar, and spices. | Cook on high for 3 to 4 hours or on low for 6 to 7 hours. | Pull the chicken. | Serve with coleslaw in buns.', instructions_es = 'Coloca los cutlets de pollo en el Crock-Pot junto con la salsa barbecue, el ketchup, el azúcar morena, el vinagre de manzana y los condimentos. | Cocina en alta de 3 a 4 horas o en baja de 6 a 7 horas. | Desmenuza el pollo. | Sírvelo en panes con coleslaw.', kosher_type = 'Meat' where name = 'Pulled Crock-Pot Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Stir-fry the chicken cutlets in oil with the garlic. | Mix together the hot water, onion soup mix, lemon juice, salt, black pepper, and flour. | Pour the sauce over the cooked chicken in the pan. | Bring to a boil and let simmer for a few minutes. | Mix the chicken and sauce with cooked fettuccine noodles.', instructions_es = 'Saltea el pollo en aceite junto con el ajo. | Mezcla el agua caliente, la mezcla de sopa de cebolla, el jugo de limón, la sal, la pimienta negra y la harina. | Vierte la salsa sobre el pollo cocido en la sartén. | Lleva a hervor y deja cocinar unos minutos. | Mezcla el pollo y la salsa con los fideos fettuccine cocidos.', kosher_type = 'Meat' where name = 'Chicken Fettuccine' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Coat the chicken cutlets in flour, stir-fry them, and set aside. | Fry the onions, broccoli, and mushrooms. | Mix together the flour, chicken stock, honey, soy sauce, and garlic. | Add the sauce to the vegetables in the pan. | Boil until thickened. | Add the chicken back to the pan. | Serve over rice or orzo.', instructions_es = 'Pasa los cutlets de pollo por harina, saltéalos y resérvalos. | Fríe las cebollas, el brócoli y los hongos. | Mezcla la harina, el caldo de pollo, la miel, la salsa de soja y el ajo. | Agrega la salsa a las verduras dentro de la sartén. | Hierve hasta que espese. | Vuelve a agregar el pollo a la sartén. | Sirve sobre arroz u orzo.', kosher_type = 'Meat' where name = 'Chicken and Veggie Stir-Fry' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté the garlic in the olive oil. | Add the chicken and cook. | Add the broccoli florets, scallions, and mushrooms. | Sprinkle the vegetables with the dried basil, salt, and pepper. | Add the chicken broth and stir to combine. | Cover and simmer 5 to 10 minutes, until the vegetables are tender. | Meanwhile, cook the bow-tie noodles, drain them, and add them to the skillet. | Toss gently and serve immediately. | Notes | Some text on the attachment was slightly cut off; this version reflects the readable content.', instructions_es = 'Saltea el ajo en el aceite de oliva. | Agrega el pollo y cocínalo. | Agrega el brócoli, los cebollines y los hongos. | Espolvorea con la albahaca seca, la sal y la pimienta. | Agrega el caldo de pollo y mezcla bien. | Tapa y cocina a fuego bajo de 5 a 10 minutos, hasta que las verduras estén tiernas. | Mientras tanto, cocina los fideos moño, escúrrelos y agrégalos a la sartén. | Mezcla suavemente y sirve enseguida. | Nota | La receta estaba parcialmente visible en el archivo original.', kosher_type = 'Meat' where name = 'Stir-Fried Chicken with Bow-Tie Noodles' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place the chicken bottoms in a pan. Arrange the potatoes next to and in between the chicken pieces. | Combine the sliced onion and the rest of the ingredients in a small bowl. Smear this mixture over the chicken and potatoes. | If preparing fresh, preheat oven to 350°F. Bake covered for 2 hours and then uncover and bake for 30 minutes until browned to your liking. | If freezing, defrost overnight in the refrigerator. In the morning, place in a 300°F oven and bake all day, covered. About an hour before serving, raise the temperature to 350°F and uncover. Bake until browned to your liking.', instructions_es = 'Coloca las piezas de pollo en una fuente. Acomoda las papas entre y al lado del pollo. | Mezcla la cebolla cortada y el resto de los ingredientes en un bowl pequeño. | Unta esta mezcla sobre el pollo y las papas. | Si lo preparas fresco, precalienta el horno a 350°F. Hornea tapado durante 2 horas y luego destapa y hornea 30 minutos más, hasta que se dore a tu gusto. | Si lo congelas, descongélalo toda la noche en la heladera. A la mañana, colócalo en horno de 300°F y cocínalo todo el día tapado. Aproximadamente 1 hora antes de servir, sube la temperatura a 350°F, destapa y hornea hasta que se dore.', kosher_type = 'Meat' where name = 'Mommy''s Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 350°F. Line a cookie sheet with parchment paper. | Toss the red potatoes in 2 tablespoons olive oil and salt. Spread on one-third of the baking sheet and bake for 20 minutes. | Whisk together the maple syrup, soy sauce, and garlic for the salmon sauce. | After 20 minutes, remove the pan from the oven. Toss the green beans in 2 tablespoons olive oil and salt and place them on another end of the baking sheet. Place the salmon in the center. | Sprinkle the salmon with salt and pepper and brush with about 2 tablespoons sauce per slice. | Return the baking sheet to the oven for 20 minutes more. | To finish, broil on high for 5 minutes.', instructions_es = 'Precalienta el horno a 350°F y forra una bandeja con papel pergamino. | Mezcla las papitas con 2 cucharadas de aceite de oliva y sal. Distribúyelas en un tercio de la bandeja y hornéalas 20 minutos. | Bate el maple, la salsa de soja y el ajo para hacer la salsa del salmón. | Después de 20 minutos, retira la bandeja del horno. Mezcla los ejotes con las 2 cucharadas restantes de aceite de oliva y sal y colócalos en otro lado de la bandeja. Pon el salmón en el centro. | Espolvorea el salmón con sal y pimienta y pincela cada porción con aproximadamente 2 cucharadas de salsa. | Vuelve a llevar la bandeja al horno por 20 minutos más. | Para terminar, gratina a temperatura alta durante 5 minutos.', kosher_type = 'Parve' where name = 'One-Pan Maple Salmon Dinner' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Pound the steak to make it soft. Cut the meat into cubes 1/4 inch thick. | Sprinkle the meat with the paprika, garlic powder, and onion powder. Let it stand for 2 minutes. | In a skillet, melt the margarine. Brown the meat in the margarine. Add the minced garlic and broth. Cover and allow the meat to simmer for 30 minutes. | Stir in the scallions, onion, and peppers. Cover and allow to simmer for an additional 15 minutes. | In a small bowl, whisk together the cornstarch, sugar, water, and soy sauce. Pour the cornstarch mixture onto the meat mixture and continue cooking until the sauce thickens, about 2 minutes. | Add the tomatoes and serve.', instructions_es = 'Golpea la carne para ablandarla. Córtala en cubos de 1/4 de pulgada de grosor. | Espolvorea la carne con el pimentón, el ajo en polvo y la cebolla en polvo. Déjala reposar 2 minutos. | En una sartén, derrite la margarina. Dora la carne en la margarina. | Agrega el ajo picado y el caldo. Tapa y deja hervir a fuego bajo durante 30 minutos. | Incorpora los cebollines, la cebolla y los pimientos. Tapa y cocina 15 minutos más. | En un bowl pequeño, bate la maicena, el azúcar, el agua y la salsa de soja. Viértelo sobre la mezcla de carne y cocina hasta que la salsa espese, unos 2 minutos. | Agrega los tomates y sirve.', kosher_type = 'Meat' where name = 'Adventures with Pepper Steak' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Dice up the onion and carrot and place them in water; boil. | Add salt, pepper, garlic powder, and lots of paprika. | Blend 1 carrot and 1 onion. | Add the blended carrot and onion to the ground chicken with 1/2 cup water, the egg, breadcrumbs, salt, pepper, garlic powder, and paprika. | Make balls, drop them into the water, and simmer for 1 hour. | Notes | The attachment read like a texted recipe note, so quantities were only given where shown.', instructions_es = 'Corta la cebolla y la zanahoria y colócalas en agua; llévalas a hervor. | Agrega sal, pimienta, ajo en polvo y bastante pimentón. | Licúa 1 zanahoria y 1 cebolla. | Agrega la zanahoria y la cebolla licuadas al pollo molido junto con 1/2 taza de agua, el huevo, el pan rallado, la sal, la pimienta, el ajo en polvo y el pimentón. | Forma bolitas, échalas al agua y cocina a fuego bajo durante 1 hora. | Nota | La receta original estaba escrita como nota de WhatsApp y solo daba cantidades en parte del texto.', kosher_type = 'Meat' where name = 'False Fish' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine all of the meatball ingredients and form into balls. | In a saucepan, combine the sauce ingredients and bring to a boil. | Gently drop the balls into the simmering sauce and cook for 45 minutes. | Serve over spaghetti.', instructions_es = 'Mezcla todos los ingredientes de las albóndigas y forma bolitas. | En una cacerola, mezcla todos los ingredientes de la salsa y llévalos a hervor. | Agrega con cuidado las bolitas a la salsa hirviendo suave y cocina durante 45 minutos. | Sirve sobre spaghetti.', kosher_type = 'Meat' where name = 'Coca-Cola Meatballs' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Whisk together the soy sauce, oil, toasted sesame oil, honey, garlic, clementine juice, red pepper flakes, salt, and black pepper to make the marinade. | Place the chicken in a zip-top bag with the marinade, seal, and refrigerate overnight or at least 6 hours. | To make the vinaigrette, combine all dressing ingredients in a jar or cruet and shake until well combined. | Remove the chicken from the marinade and grill or broil for 6 to 8 minutes per side. | In a large bowl, combine the baby arugula, red onion, endive, pomegranate seeds, sunflower seeds, sliced almonds, and sliced clementines. | Drizzle the salad with vinaigrette, arrange the chicken on top or on the side, and sprinkle with black sesame seeds before serving. | Notes | A few words on the attachment were small, but the ingredients and method were readable enough to reconstruct this clean version.', instructions_es = 'Bate la salsa de soja, el aceite, el aceite de sésamo, la miel, el ajo, el jugo de clementina, las hojuelas de ají, la sal y la pimienta para hacer la marinada. | Coloca el pollo en una bolsa con cierre junto con la marinada, ciérrala y llévala a la heladera toda la noche o por lo menos 6 horas. | Para hacer la vinagreta, mezcla todos los ingredientes en un frasco o salsera con tapa y agita bien. | Retira el pollo de la marinada y ásalo o gratínalo de 6 a 8 minutos por lado. | En un bowl grande, mezcla la rúcula, la cebolla roja, la endivia, las semillas de granada, las semillas de girasol, las almendras y las rodajas de clementina. | Rocía la ensalada con la vinagreta, acomoda el pollo por encima o al costado y espolvorea con semillas de sésamo negro antes de servir.', kosher_type = 'Meat' where name = 'Clementine Glazed Chicken and Baby Arugula Salad with Balsamic-Soy Vinaigrette' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Dip each veal chop into the seasoned breadcrumbs, then into egg, then again into the breadcrumbs. | Freeze the chops individually in zip-top bags until ready to bake. | Bake until cooked through; the attachment noted that this supper takes about 90 minutes from oven to table. | Notes | The attachment described the breading method clearly but did not show a complete temperature or full baking method.', instructions_es = 'Pasa cada chuleta de ternera por el pan rallado condimentado, luego por huevo y después nuevamente por el pan rallado. | Congela cada chuleta por separado en bolsas con cierre hasta el momento de hornear. | Hornea hasta que estén bien cocidas. La nota original decía que esta cena tarda unos 90 minutos desde que entra al horno hasta la mesa. | Nota | El archivo original no mostraba temperatura exacta ni método de cocción completo.', kosher_type = 'Meat' where name = 'Breaded Veal Chops' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Season the flanken roast with salt, pepper, garlic powder, and herbed sea salt. | Drizzle with soy sauce. | Add a drop of liquid hickory smoke. | Sprinkle onion soup mix over the meat. | Top with sliced onions. | Add a little Jim Beam maple hickory BBQ sauce. | Cover tightly three times. | Bake at 250°F for 5 to 6 hours.', instructions_es = 'Sazona el roast de flanken con sal, pimienta, ajo en polvo y sal marina con hierbas. | Rocía con salsa de soja. | Agrega una gota de humo líquido. | Espolvorea mezcla para sopa de cebolla sobre la carne. | Cubre con las cebollas en rodajas. | Agrega un poco de salsa BBQ Jim Beam maple hickory. | Cubre bien tres veces. | Hornea a 250°F durante 5 a 6 horas.', kosher_type = 'Meat' where name = 'Flanken Roast' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place the onions and half the tomatoes in a large roasting pan. | Place the roast on top and cover with the remaining onions and tomatoes, the duck sauce, wine, and spices. | Cover and refrigerate for at least 2 hours, or preferably overnight. | Preheat the oven to 375°F. | Bring the roast to room temperature. | Bake covered for about 3.5 hours, until tender when pierced with a fork. | Remove from the oven and cool. | Transfer to a cutting board and slice thinly across the grain with a sharp knife. | For gravy, blend the tomatoes and onions with the sauce.', instructions_es = 'Coloca las cebollas y la mitad de los tomates en una fuente grande para horno. | Pon el roast encima y cúbrelo con el resto de las cebollas y los tomates, la salsa de pato, el vino y las especias. | Tapa y refrigera durante al menos 2 horas, o preferiblemente toda la noche. | Precalienta el horno a 375°F. | Deja que el roast llegue a temperatura ambiente. | Hornea tapado durante unas 3.5 horas, hasta que esté tierno al pincharlo con un tenedor. | Retira del horno y deja enfriar. | Pasa a una tabla y córtalo finamente en contra de la fibra con un cuchillo afilado. | Para la salsa, licúa los tomates y las cebollas con el jugo de cocción.', kosher_type = 'Meat' where name = 'French Roast' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 425°F. | Place the brisket into a roasting pan. | Combine the remaining ingredients in a 4-quart saucepan and cook over low heat for 10 minutes, stirring occasionally. | Pour the sauce over the meat in the pan. Cover and seal the pan tightly. | Bake for 15 minutes. | Reduce the oven temperature to 200°F. Bake overnight or for at least 6 hours. | Remove the pan from the oven and let it cool enough to handle. | If desired, remove the fat from the meat and discard. | Use two forks to shred the meat. | Rewarm the shredded meat in the sauce before serving. | Notes | Overlay note on the image suggested reheating right before Shabbos at 210° and serving on a platter with shredded meat, crackers, and sauce.', instructions_es = 'Precalienta el horno a 425°F. | Coloca el brisket en una fuente para horno. | Mezcla los demás ingredientes en una cacerola de 4 cuartos y cocina a fuego bajo durante 10 minutos, revolviendo de vez en cuando. | Vierte la salsa sobre la carne. Tapa y sella bien la fuente. | Hornea durante 15 minutos. | Baja la temperatura del horno a 200°F. Hornea toda la noche o por lo menos 6 horas. | Retira del horno y deja enfriar hasta poder manipularlo. | Si deseas, retira la grasa de la carne y deséchala. | Desmenuza la carne con dos tenedores. | Vuelve a calentar la carne desmenuzada en la salsa antes de servir. | Notas | La nota sobre la imagen sugería recalentar justo antes de Shabbos a 210° y servir en una fuente con la carne desmenuzada, galletas saladas y salsa.', kosher_type = 'Meat' where name = 'Pulled Brisket' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Pour 1 cup of water on the bottom of the pan. | Place the corned beef in the pan. | Sprinkle 1 cup brown sugar on top. | Sprinkle 3 tablespoons balsamic vinegar on top. | Cover and bake at 400°F for 3 hours.', instructions_es = 'Vierte 1 taza de agua en el fondo de la fuente. | Coloca el corned beef en la fuente. | Espolvorea 1 taza de azúcar morena por encima. | Rocía 3 cucharadas de vinagre balsámico por encima. | Tapa y hornea a 400°F durante 3 horas.', kosher_type = 'Meat' where name = 'Simple and Delicious Corned Beef' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 350°F. | In a small saucepan, combine the sauce ingredients, adjusting the amount of brown sugar to the desired level of sweetness. | Bring to a boil over medium-high heat, stirring continuously. | Transfer the tongue to a baking pan and pour the sauce over it. | Bake covered for 20 minutes. | Serve warm.', instructions_es = 'Precalienta el horno a 350°F. | En una cacerola pequeña, mezcla los ingredientes de la salsa, ajustando la cantidad de azúcar morena según el nivel de dulzor que quieras. | Lleva a hervor a fuego medio-alto, revolviendo continuamente. | Coloca la lengua en una fuente para horno y vierte la salsa por encima. | Hornea tapado durante 20 minutos. | Sirve caliente.', kosher_type = 'Meat' where name = 'Tongue Polonaise' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'For pan-searing: Heat several tablespoons of olive oil in a large nonstick pan over medium-high heat. | Rub kosher salt, pepper, and frozen garlic cubes on both sides of the steak. | Sear for about 6 to 7 minutes on each side. | For grilling: Rub the oyster steaks with olive oil and season with salt, pepper, and frozen garlic cubes. | Grill for 6 to 7 minutes on each side, then let rest for several minutes. | Slice and drizzle with chimichurri, pesto sauce, or flavored garlic or truffle mayonnaise, if desired. | For a more well-done result, bake uncovered in a preheated 350°F oven until the desired internal temperature is reached.', instructions_es = 'Para hacerlos en sartén: calienta varias cucharadas de aceite de oliva en una sartén antiadherente grande a fuego medio-alto. | Frota ambos lados del filete con sal kosher, pimienta y cubos de ajo congelado. | Sella durante unos 6 a 7 minutos por lado. | Para hacerlos a la parrilla: frota los filetes con aceite de oliva y sazona con sal, pimienta y cubos de ajo congelado. | Ásalos de 6 a 7 minutos por lado y luego déjalos reposar varios minutos. | Córtalos y rocíalos con chimichurri, pesto o mayonesa saborizada con ajo o trufa, si deseas. | Para un punto más cocido, hornéalos destapados en un horno precalentado a 350°F hasta alcanzar la cocción deseada.', kosher_type = 'Meat' where name = 'Oyster Steaks' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Season the breadcrumbs with salt, pepper, paprika, and garlic powder. | Dip each veal chop into the breadcrumbs. | Dip into egg. | Dip again into the breadcrumbs. | Freeze individually in Ziploc bags until ready to bake. | Bake and serve when desired; the image notes that dinner is ready about 90 minutes after placing in the oven. | Notes | The screenshot did not show an exact oven temperature.', instructions_es = 'Sazona el pan rallado con sal, pimienta, pimentón y ajo en polvo. | Pasa cada chuleta de ternera por el pan rallado. | Pásala por huevo. | Vuelve a pasarla por pan rallado. | Congela cada una por separado en bolsas Ziploc hasta el momento de hornear. | Hornea y sirve cuando desees; la imagen decía que la cena queda lista unos 90 minutos después de ponerla en el horno. | Notas | La imagen no mostraba la temperatura exacta del horno.', kosher_type = 'Meat' where name = 'Breaded Veal Chops' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 350°F. | Season the ribs and bake covered for 2 hours. | Reserve the juice from the pan and mix it with the sauce ingredients. | Pour the sauce over the ribs and bake uncovered for 30 minutes. | Bake longer, until the meat is tender. | Notes | The last line of the note appears to say to bake longer until the meat softens/tenders.', instructions_es = 'Precalienta el horno a 350°F. | Sazona las costillas y hornéalas tapadas durante 2 horas. | Reserva el jugo de la fuente y mézclalo con los ingredientes de la salsa. | Vierte la salsa sobre las costillas y hornea destapado durante 30 minutos. | Hornea más tiempo, hasta que la carne esté tierna. | Notas | La última línea de la nota parece indicar que hay que hornear más tiempo hasta que la carne se ablande.', kosher_type = 'Meat' where name = 'Asian Ribs' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sprinkle the roast with olive oil, salt, pepper, garlic powder, and onion powder. | Pour the oil and Dijon mustard mixture over the roast. | Bake 20 minutes at 500°F, uncovered. | Lower the oven to 350°F and continue baking for 20 minutes per pound, covered.', instructions_es = 'Rocía el asado con aceite de oliva, sal, pimienta, ajo en polvo y cebolla en polvo. | Vierte encima la mezcla de aceite y mostaza Dijon. | Hornea destapado 20 minutos a 500°F. | Baja el horno a 350°F y continúa horneando 20 minutos por libra, tapado.', kosher_type = 'Meat' where name = 'Standing Rib Roast' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Rub the ribs with olive oil, salt, and pepper. | Mix together the ketchup, honey, brown sugar, vinegar, Worcestershire sauce, white pepper, chili powder, garlic, and cayenne to make the sauce. | Heat the oven to 350°F. | Cover the ribs tightly and bake for about 3 hours. | Uncover, brush with sauce, and continue baking until done.', instructions_es = 'Frota las costillas con aceite de oliva, sal y pimienta. | Mezcla el ketchup, la miel, el azúcar morena, el vinagre, la salsa Worcestershire, la pimienta blanca, el chili en polvo, el ajo y la cayena para hacer la salsa. | Calienta el horno a 350°F. | Tapa bien las costillas y hornéalas durante unas 3 horas. | Destapa, pincela con la salsa y sigue horneando hasta que estén listas.', kosher_type = 'Meat' where name = 'Rack of Ribs' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 450°F. | Place the marrow bones on a tray or ovenproof skillet, bone side down. | Roast until the bones are lightly browned, about 20 minutes. | Some fat will render from the bones, but most of the marrow should stay in the bone. | Serve immediately, with bread and a sharp green salad on the side. | Notes | Only part of the ingredient list was visible in the screenshot.', instructions_es = 'Precalienta el horno a 450°F. | Coloca los huesos de tuétano en una bandeja o sartén apta para horno, con el lado del hueso hacia abajo. | Ásalos hasta que estén ligeramente dorados, unos 20 minutos. | Parte de la grasa se derretirá, pero la mayor parte del tuétano debe quedar dentro del hueso. | Sirve de inmediato, con pan tostado y una ensalada verde con buen sabor al lado. | Notas | Solo se veía una parte de la lista de ingredientes en la imagen.', kosher_type = 'Meat' where name = 'Roasted Marrow Bones' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Pour BBQ sauce over a piece of cheek meat. | Bake low and slow overnight at 200°F for about 8 to 10 hours. | Pour the sauce into a pan, add some red wine, and reduce it. | Pour the reduced sauce back into the meat. | Pull or shred the meat. | Fill mini tacos and serve. | Notes | The visible caption was truncated, so only the readable portion was included.', instructions_es = 'Vierte salsa BBQ sobre un trozo de carrillera. | Hornea a fuego bajo toda la noche a 200°F durante unas 8 a 10 horas. | Pasa la salsa a una sartén, agrega un poco de vino tinto y redúcela. | Vierte la salsa reducida nuevamente sobre la carne. | Deshebra la carne. | Rellena los mini tacos y sirve. | Notas | El texto visible estaba cortado, por lo que solo se incluyó la parte legible.', kosher_type = 'Meat' where name = 'Red Wine BBQ Cheek Meat Tacos' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place the ground meat in a frying pan sprayed with Pam. | Let it cook and do not drain the liquid. | Add the brown sugar, cumin, garlic powder, and salt. | Let the liquid cook off. | Pour in a whole jar of marinara sauce. | Cook on a low flame until the sauce is evaporated. | Notes | The lower part of the note was cut off in the screenshot, so this document includes only the visible portion.', instructions_es = 'Coloca la carne molida en una sartén rociada con Pam. | Déjala cocinar y no escurras el líquido. | Agrega el azúcar morena, el comino, el ajo en polvo y la sal. | Deja que el líquido se evapore. | Vierte un frasco entero de salsa marinara. | Cocina a fuego bajo hasta que la salsa se evapore. | Notas | La parte inferior de la nota estaba cortada en la imagen, por lo que este documento incluye solo la parte visible.', kosher_type = 'Meat' where name = 'Chummus Bassar' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Pat the steaks dry, then sprinkle generously with salt and pepper. | Sear over medium heat until golden brown. | Transfer to a disposable pan and generously cover the meat with the duck sauce. | Bake for 1 1/2 hours covered, then 15 minutes uncovered. | For the duck sauce: cook all ingredients for 45 minutes in a covered pot, then uncover and let simmer for another 30 minutes. Let cool and blend to the desired consistency.', instructions_es = '', kosher_type = 'Meat' where name = 'Sweetened Veal Steak' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Preheat oven to 350°F. Grease a roasting pan. | 2. Place chicken into the prepared pan. | 3. Season lightly with sea salt, garlic powder, onion powder, and paprika. | 4. Spread mayonnaise over the chicken. | 5. Sprinkle with cornflake crumbs to evenly cover. | 6. Cover and bake on the center rack for 1 hour 20 minutes. | 7. Meanwhile, combine the sauce ingredients in a small bowl. | 8. Remove the pan from the oven and pour the accumulated liquid into a small bowl. Allow liquid to cool, then discard. | 9. Pour the sauce over the chicken and return the pan to the oven. | 10. Bake uncovered for 20–30 minutes, until tender. | Note | You can also use chicken bottoms separated into drumsticks and thighs.', instructions_es = 'Precalienta el horno a 350°F. Engrasa una fuente para horno. | Coloca el pollo en la fuente preparada. | Sazona ligeramente con sal marina, ajo en polvo, cebolla en polvo y pimentón. | Unta la mayonesa sobre el pollo. | Espolvorea las migas de cornflakes de manera uniforme para cubrir. | Tapa y hornea en la rejilla del centro durante 1 hora y 20 minutos. | Mientras tanto, mezcla los ingredientes de la salsa en un tazón pequeño. | Retira la fuente del horno y vierte el líquido acumulado en un tazón pequeño. Deja que se enfríe y luego deséchalo. | Vierte la salsa sobre el pollo y vuelve a llevar la fuente al horno. | Hornea destapado durante 20 a 30 minutos, hasta que esté tierno. | Nota | También puedes usar presas separadas en muslos y patas.', kosher_type = 'Meat' where name = 'Eileen’s Sweet and Tangy Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Whisk together the eggs, water, flour, and salt. | 2. Coat and fry the chicken cutlets. | 3. Sauté the onion, green pepper, red pepper, and mushrooms. | 4. Add the apricot jam, ketchup, and brown sugar. | 5. Pour the sauce over the fried cutlets. | 6. Bake uncovered. | Note | The screenshot did not show the oven temperature or baking time.', instructions_es = 'Bate los huevos, el agua, la harina y la sal hasta integrar. | Cubre los cutlets de pollo con la mezcla y fríelos. | Saltea la cebolla, el pimiento verde, el pimiento rojo y los champiñones. | Agrega la mermelada de albaricoque, el ketchup y el azúcar morena. | Vierte la salsa sobre los cutlets fritos. | Hornea destapado. | Nota | En la imagen no aparecían la temperatura del horno ni el tiempo de cocción.', kosher_type = 'Meat' where name = 'Saucy Chicken Cutlets – EN Steg.' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. In a 9x13 pan, combine the rice, water, and onion soup mix. Stir well. | 2. Top with 4 pieces of chicken. | 3. Mix together the ketchup, brown sugar, vinegar, soy sauce, and garlic. | 4. Brush or spoon the sauce over the chicken. | 5. Sprinkle with sesame seeds, if using. | 6. Cover tightly with a 9x13 lid or tin foil. | 7. Bake for 3 hours at 350°F.', instructions_es = 'En una fuente de 9x13, mezcla el arroz, el agua y la mezcla para sopa de cebolla. Revuelve bien. | Coloca encima las 4 piezas de pollo. | Mezcla el ketchup, el azúcar morena, el vinagre, la salsa de soja y el ajo. | Pincela o vierte la salsa sobre el pollo. | Espolvorea semillas de sésamo, si las usas. | Cubre bien con tapa o papel aluminio. | Hornea durante 3 horas a 350°F.', kosher_type = 'Meat' where name = 'One Pan Chicken and Rice' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Soak cedar plank in water for 1 hour. When ready to use, remove from the water and proceed with recipe. Do not pat dry. | Place the first 6 ingredients in a saucepan; bring to a slow boil. Remove from the heat and let cool slightly. | Place the salmon in a shallow dish. Reserving about 1/4 cup, pour the glaze over the salmon. Marinate at room temperature for 30 minutes. | Preheat the oven to 400°F. | Place the cedar plank directly on the middle rack in the oven and bake for 8 to 10 minutes or until the wood is lightly toasted. Remove the plank from the oven. While still hot, brush with a thin coating of olive oil. | Remove the salmon from the marinade; discard the marinade. Place the salmon directly on the hot plank and then in a shallow roasting pan. | Roast in the center of the preheated oven for 20 to 25 minutes, basting with the reserved 1/4 cup during the last 10 minutes or until the fish flakes easily with a fork. Glaze the fish with the reserved sauce.', instructions_es = 'Remoja la tabla de cedro en agua durante 1 hora. Cuando vayas a usarla, sácala del agua y sigue con la receta. No la seques. | Coloca los primeros 6 ingredientes en una cacerola y llévalos a hervor suave. Retira del fuego y deja enfriar un poco. | Pon el salmón en una fuente poco profunda. Reserva aproximadamente 1/4 de taza del glaseado y vierte el resto sobre el salmón. Déjalo marinar a temperatura ambiente durante 30 minutos. | Precalienta el horno a 400°F. | Coloca la tabla de cedro directamente sobre la rejilla central del horno y hornéala de 8 a 10 minutos, o hasta que la madera esté ligeramente tostada. Retírala del horno. Mientras aún esté caliente, pincélala con una capa fina de aceite de oliva. | Retira el salmón de la marinada y desecha la marinada. Coloca el salmón directamente sobre la tabla caliente y luego sobre una fuente para horno. | Hornea en el centro del horno precalentado durante 20 a 25 minutos, pincelando con el 1/4 de taza reservado durante los últimos 10 minutos, o hasta que el pescado se desmenuce fácilmente con un tenedor. Baña con el glaseado reservado antes de servir.', kosher_type = 'Parve (Fish)' where name = 'Cedar Plank Salmon with Maple Glaze' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a small bowl, stir together maple syrup, soy sauce, garlic, and lemon juice. | Preheat oven to 425°F. Line a rimmed baking sheet with parchment paper or foil. | Arrange salmon in a single layer on prepared pan. Pour sauce over fish. Let stand for 20 minutes if desired. | Bake, uncovered, for 12–15 minutes, basting once or twice, until salmon is glazed and golden. Serve hot or at room temperature. | Recipe Note | The screenshot included a handwritten note: bring the maple syrup to a boil first in a cool, dry saucepan before adding the other ingredients. Once opened, maple syrup can be refrigerated for short-term storage or frozen for longer storage.', instructions_es = 'En un bowl pequeño, mezcla el jarabe de maple, la salsa de soja, el ajo y el jugo de limón. | Precalienta el horno a 425°F. Forra una bandeja con papel pergamino o aluminio. | Acomoda el salmón en una sola capa sobre la bandeja preparada. Vierte la salsa sobre el pescado. Si deseas, deja reposar 20 minutos. | Hornea destapado durante 12 a 15 minutos, bañando una o dos veces con la salsa, hasta que el salmón esté glaseado y dorado. Sirve caliente o a temperatura ambiente. | Nota de la receta | La imagen incluía una nota escrita a mano: primero llevar el jarabe de maple a hervor en una cacerola limpia y seca antes de añadir los demás ingredientes. Una vez abierto, el maple puede refrigerarse por poco tiempo o congelarse para conservarse más tiempo.', kosher_type = 'Parve (Fish)' where name = 'Maple-Glazed Salmon' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 375°F. | Place the soy sauce and sugar into a medium pot. Bring to a boil. Add the ginger, garlic, and whiskey. Reduce the heat to low and simmer for 5 minutes. Remove half the sauce to a container to drizzle over the fish after it is cooked. Set aside. | Brush a broiling pan with olive oil. | Season the salmon fillets with salt and pepper. Place them on the prepared pan. Sprinkle 1 tablespoon of crushed pineapple over each fillet. Drizzle 1 tablespoon of the soy sauce mixture over the top of each fillet. | Bake, uncovered, for about 20–25 minutes, until the salmon is pink and slightly firm to the touch. | Drizzle with the reserved sauce before serving.', instructions_es = 'Precalienta el horno a 375°F. | Coloca la salsa de soja y el azúcar en una cacerola mediana. Lleva a hervor. Agrega el jengibre, el ajo y el whiskey. Baja el fuego y cocina a fuego lento durante 5 minutos. Retira la mitad de la salsa a un recipiente para usarla al final sobre el pescado. | Pincela una fuente o bandeja para asar con aceite de oliva. | Sazona los filetes de salmón con sal y pimienta. Colócalos en la fuente preparada. Pon 1 cucharada de piña triturada sobre cada filete. Rocía 1 cucharada de la salsa de soja sobre cada uno. | Hornea destapado durante unos 20 a 25 minutos, hasta que el salmón esté rosado y apenas firme al tacto. | Rocía con la salsa reservada antes de servir.', kosher_type = 'Parve (Fish)' where name = 'Lacquered Salmon' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 375°F. Spray a broiler pan with nonstick cooking spray. | Place the salmon on the broiler pan. Season with fine sea salt and pepper. Toss the mushrooms with 1 tablespoon olive oil and arrange them around the salmon. | Roast for 25 minutes. Set aside. | Meanwhile, place the remaining 3 tablespoons olive oil into a large soup pot over medium heat. Add orzo and stir to coat with warm oil. Toast until lightly browned and fragrant, stirring occasionally. | Add water to come up halfway in the pot. Add 2 tablespoons fine or coarse sea salt and bring to a boil. Cook orzo until tender, usually 9–11 minutes. Drain and rinse orzo and set aside in a medium bowl. | Place basil leaves into a quart-sized or other high-sided container. Add pistachios, 1 cup extra-virgin olive oil, and a pinch of fine sea salt. Using an immersion blender, purée the mixture. This can also be done in a food processor. | Pour half of this pesto into the orzo. Break the salmon into chunks and add it to the orzo. Add the mushrooms and artichokes. Season with 1/2 teaspoon fine sea salt. Toss to combine. | Place into a bowl or serving platter and drizzle with remaining pesto. | Best served warm or at room temperature. | Note | The screenshot caption said the pesto is especially good and that artichokes can be skipped if desired.', instructions_es = 'Precalienta el horno a 375°F. Rocía una bandeja para asar con spray antiadherente. | Coloca el salmón en la bandeja. Sazónalo con sal fina y pimienta. Mezcla los champiñones con 1 cucharada de aceite de oliva y colócalos alrededor del salmón. | Hornea durante 25 minutos. Reserva. | Mientras tanto, coloca las 3 cucharadas restantes de aceite de oliva en una olla grande a fuego medio. Agrega el orzo y revuelve para cubrirlo con el aceite caliente. Tuéstalo ligeramente, revolviendo de vez en cuando, hasta que esté apenas dorado y fragante. | Agrega agua hasta cubrir más o menos la mitad del contenido de la olla. Añade 2 cucharadas de sal marina fina o gruesa y lleva a hervor. Cocina el orzo hasta que esté tierno, generalmente de 9 a 11 minutos. Escúrrelo, enjuágalo y colócalo en un bowl mediano. | Pon las hojas de albahaca en un recipiente alto. Agrega los pistachos, 1 taza de aceite de oliva extra virgen y una pizca de sal marina fina. Tritura con batidora de inmersión o procesador. | Vierte la mitad del pesto sobre el orzo. Desmenuza el salmón en trozos y agrégalo al orzo. Incorpora los champiñones y las alcachofas. Añade 1/2 cucharadita de sal marina fina. Mezcla bien. | Pasa a una fuente o bowl para servir y rocía con el resto del pesto. | Se sirve mejor tibio o a temperatura ambiente. | Nota | La publicación original decía que el pesto queda especialmente bien y que las alcachofas se pueden omitir si lo prefieres.', kosher_type = 'Parve (Fish)' where name = 'Basil Pesto Glazed Orzo, Salmon, and Artichokes' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a deep skillet, combine sugar and onions. Cook over low heat, stirring occasionally, until sugar melts. Continue cooking for 5–7 minutes, until onions soften. | Add water, salt, and lemon juice. Raise heat to medium-high; bring to a boil. Add salmon; reduce heat to medium. Cover pan; cook 25–30 minutes. | Serve warm or chilled.', instructions_es = 'En una sartén honda, combina el azúcar y las cebollas. Cocina a fuego bajo, revolviendo de vez en cuando, hasta que el azúcar se derrita. Sigue cocinando de 5 a 7 minutos, hasta que las cebollas se ablanden. | Agrega el agua, la sal y el jugo de limón. Sube el fuego a medio-alto y lleva a hervor. Añade el salmón, baja a fuego medio y tapa. Cocina de 25 a 30 minutos. | Sirve caliente o frío.', kosher_type = 'Parve (Fish)' where name = 'Pickled Salmon' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Add 1 cup sugar and the sliced onion to a pot. Cook until the sugar melts, then mix together and add the remaining ingredients. | Bring to a low boil, then add the fish. | Cook another 20–30 minutes, being careful not to overcook. | Serve cool. | Mayo Sauce | Mayonnaise | Chives or dill | Garlic powder | Water, to thin', instructions_es = 'Agrega 1 taza de azúcar y la cebolla en rodajas a una olla. Cocina hasta que el azúcar se derrita, luego mezcla y añade el resto de los ingredientes. | Lleva a hervor suave y luego agrega el pescado. | Cocina otros 20 a 30 minutos, cuidando no pasarlo de cocción. | Sirve frío. | Salsa de mayonesa | Mayonesa | Ciboulette o eneldo | Ajo en polvo | Agua, para aligerar', kosher_type = 'Parve (Fish)' where name = 'Royal Salmon Recipe' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat broiler to high. | Combine cheese, butter, mayonnaise, and scallions. | Place fish in a lightly greased pan. | Squeeze juice of 1 lemon over fillets and sprinkle with black pepper. | Broil about 6 inches from the heat for 10 minutes. | Remove from oven. Spread the Parmesan mixture over the fish. | Broil 2 minutes more, or until lightly browned and bubbly.', instructions_es = 'Precalienta el gratinador del horno a temperatura alta. | Mezcla el queso, la mantequilla, la mayonesa y los cebollines. | Coloca el pescado en una fuente ligeramente engrasada. | Exprime el jugo de 1 limón sobre los filetes y espolvorea con pimienta negra. | Gratina a unas 6 pulgadas del calor durante 10 minutos. | Retira del horno y extiende la mezcla de parmesano sobre el pescado. | Gratina 2 minutos más, o hasta que esté ligeramente dorado y burbujeante.', kosher_type = 'Parve (Fish)' where name = 'Parmesan-Crusted Grouper (or Sea Bass)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place fillets in a baking dish or on a baking sheet. | Top with capers, butter, lemon, thyme, salt, and pepper. | Bake until the fish is cooked through and flakes easily. | Note | The original screenshot was a dinner story with no exact oven temperature or time shown.', instructions_es = 'Coloca los filetes en una fuente para horno o en una bandeja. | Cubre con alcaparras, mantequilla, limón, tomillo, sal y pimienta. | Hornea hasta que el pescado esté cocido y se desmenuce fácilmente. | Nota | La imagen original era una historia de comida y no mostraba temperatura ni tiempo exactos.', kosher_type = 'Parve (Fish)' where name = 'Lemon Caper Fish' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Add all sauce ingredients to a bowl and mix together. Set aside. | Add the cut tuna, green onions, and sesame seeds directly to the bowl of sauce and mix until combined. | In a separate bowl, mix together the finely chopped avocado, cucumber, cilantro, lime juice, salt, and pepper. | Plate the tartare using a mold, or by arranging it free-form, and serve.', instructions_es = 'Mezcla todos los ingredientes de la salsa en un bowl y reserva. | Agrega el atún, los cebollines y las semillas de sésamo directamente al bowl con la salsa y mezcla bien. | En otro bowl, mezcla el aguacate, el pepino, el cilantro, el jugo de lima, la sal y la pimienta. | Sirve el tartar usando un aro o molde, o acomódalo libremente en el plato.', kosher_type = 'Parve (Fish)' where name = 'Tuna Tartare in Sesame Ginger Sauce' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté onions in oil until soft. | Add peppers and sauté on high for about 20 minutes, stirring every few minutes. | Add tomatoes and sauté for another 5 minutes. | Add spices and the rest of the ingredients. Cover and cook for 45 minutes on low. | Place salmon fillet slices in a pan and pour the vegetable sauce over them. Cover pan and bake in a preheated 350°F oven for 1 hour. | Serve warm.', instructions_es = 'Saltea las cebollas en aceite hasta que estén tiernas. | Agrega los pimientos y saltea a fuego alto durante unos 20 minutos, revolviendo cada pocos minutos. | Añade los tomates y cocina 5 minutos más. | Agrega las especias y el resto de los ingredientes. Tapa y cocina a fuego bajo durante 45 minutos. | Coloca las rodajas de salmón en una fuente y vierte encima la salsa de verduras. Tapa y hornea en horno precalentado a 350°F durante 1 hora. | Sirve caliente.', kosher_type = 'Parve (Fish)' where name = 'Salmon with Vegetable Sauce' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 400°F. Line a baking sheet with parchment paper. | Place salmon on prepared baking sheet. In a small bowl, combine oil and spices. Pat onto fish; roast for 12–15 minutes, or until the edges are browned and crisp and the fish flakes easily. | Prepare the gremolata. In a small bowl, toss together parsley, pomegranate seeds, garlic, pistachios, lemon rind, and salt. | Top salmon with gremolata and serve. | Try This | Substitute za’atar with 1 tablespoon honey plus 2 tablespoons maple syrup. | Note | Za’atar is a blend that has many adaptations; look for one with hyssop leaves and sumac.', instructions_es = 'Precalienta el horno a 400°F. Forra una bandeja con papel pergamino. | Coloca el salmón en la bandeja preparada. En un bowl pequeño, mezcla el aceite y las especias. Presiona esta mezcla sobre el pescado y hornea de 12 a 15 minutos, hasta que los bordes estén dorados y crujientes y el pescado se desmenuce fácilmente. | Prepara la gremolata mezclando el perejil, las semillas de granada, el ajo, los pistachos, la ralladura de limón y la sal. | Sirve el salmón cubierto con la gremolata. | Prueba esto | Puedes sustituir el za’atar por 1 cucharada de miel más 2 cucharadas de jarabe de maple. | Nota | El za’atar es una mezcla con muchas variantes; busca una que contenga hojas de hisopo y zumaque.', kosher_type = 'Parve (Fish)' where name = 'Za’atar Salmon with Pomegranate Gremolata' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 425°F. | Soak salmon in lemon juice for 10 minutes. Wash with cold water. Pat dry and place on a baking sheet lined with parchment paper. | Combine all marinade ingredients. Pour over salmon. | Combine all crumb ingredients in a food processor. Blend until just combined. Crumbs can be prepared in advance and frozen until needed. Any leftover crumbs can also be frozen and used on individual slices of salmon. Top salmon with a generous layer of crumbs. | Bake for 30–40 minutes. After 10 minutes, place a loose piece of aluminum foil over the fish so that the crumbs do not burn. | Prepare the dressing. Blend all ingredients together using an immersion blender or food processor. | Serve fish on a platter at room temperature with dressing on the side.', instructions_es = 'Precalienta el horno a 425°F. | Remoja el salmón en jugo de limón durante 10 minutos. Enjuágalo con agua fría, sécalo y colócalo en una bandeja forrada con papel pergamino. | Mezcla todos los ingredientes de la marinada y viértela sobre el salmón. | Procesa todos los ingredientes de las migas hasta que estén apenas integrados. Puedes prepararlas con anticipación y congelarlas. Cubre el salmón generosamente con esta mezcla. | Hornea de 30 a 40 minutos. Después de 10 minutos, cubre el pescado con una hoja suelta de aluminio para que las migas no se quemen. | Prepara el aderezo licuando todos los ingredientes con batidora de inmersión o procesador. | Sirve el pescado en una fuente, a temperatura ambiente, con el aderezo aparte.', kosher_type = 'Parve (Fish)' where name = 'Side of Salmon' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Fry the onions, scallions, and celery over a low flame. | Add sliced carrots. | Put the chicken on the bone in a net and place it in the pot. | Add water, salt, and any spices you want. Bring to a boil. | Once it boils, lower the flame and cook for 50 minutes to 1 hour. | Take out the chicken and cut it into small pieces. | Return the chicken to the pot, then add the squash and cook for another 40 minutes. | Notes | Some quantities were not specified in the screenshot and are preserved as originally written.', instructions_es = 'Calienta aceite en una olla. Agrega las cebollas y déjalas cocinar hasta que estén transparentes. Agrega sal. | Corta el zucchini y la coliflor en cubos, agrégalos a la olla y vuelve a salar. | Cocina hasta que las verduras se ablanden. | Agrega lentamente agua hasta cubrir. Añade los condimentos, tapa y deja hervir suavemente de 30 a 60 minutos. | Cuando todo esté blando, licúa hasta obtener una crema suave.', kosher_type = 'Meat' where name = 'Elisheva Vegetable Chicken Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Heat oil in a pot. Add the onions and let them steam until translucent. Add salt. | Cube the zucchini and cauliflower, add to the pot, and add salt again. Cook until the vegetables soften. | Slowly add water to cover. Add the seasonings, cover, and let simmer for 30–60 minutes. | Once softened, blend into a smooth purée.', instructions_es = 'Precalienta el horno a 400°F. | En una fuente para horno, asa las cebollas picadas y el ajo con la mantequilla, destapado, durante 1 hora, revolviendo una vez. | Pasa la mezcla a una olla lenta de 5 cuartos y agrega el caldo, el vino, la salsa Worcestershire, el vinagre balsámico, la hoja de laurel, la sal, la pimienta y el tomillo. | Tapa y cocina en baja hasta que las cebollas estén muy tiernas, al menos 6 horas. Puede cocinarse hasta 10 a 12 horas. | Unos 15 minutos antes de servir, prepara las rebanadas de baguette: precalienta el horno a 450°F, acomódalas en una bandeja y hornéalas unos 5 minutos hasta tostarlas. | Retíralas, cúbrelas con queso rallado y vuelve a hornear hasta que el queso esté dorado y burbujeante, unos 10 minutos. | Para servir, coloca un poco de queso rallado en cada bowl, llena con sopa y deja que el queso se derrita. Termina con las rebanadas de baguette tostadas.', kosher_type = 'Parve' where name = 'Cauliflower Zucchini Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 400°F. In a roasting pan, roast the chopped onions and minced garlic with the butter, uncovered, for 1 hour, stirring the onions and garlic with the butter once. | Transfer the roasted onion mixture to a 5-quart slow cooker and add the stock, wine, Worcestershire sauce, balsamic vinegar, bay leaf, salt, black pepper, and thyme. Cover and cook on low until the onions are very tender, at least 6 hours. The soup can be cooked for up to 10–12 hours. | About 15 minutes before serving, prepare the baguette slices: Preheat the oven to 450°F. Arrange the baguette slices on a cookie sheet and bake until toasted, about 5 minutes. Remove from the oven, top with shredded cheese, and bake until the cheese is browned and bubbling, about 10 minutes. | To serve, place some shredded cheese in each bowl, fill with soup, and allow the cheese to melt. Top with the toasted baguettes. | Notes | Serves 8.', instructions_es = 'Calienta el aceite en una olla grande. Agrega la cebolla y el ajo y saltea a fuego alto hasta que la cebolla esté transparente y blanda, unos 8 a 10 minutos. | Agrega el zucchini, baja el fuego a medio y añade el agua. | Coloca el pollo en una bolsa para sopa y agrégalo a la olla. Agrega los condimentos y cocina durante 1 1/2 horas, hasta que el pollo esté blando. | Retira la bolsa con el pollo. Licúa la sopa con una batidora de inmersión hasta que quede suave. | Agrega lentamente la mezcla de maicena para espesar. | Retira el pollo del hueso, córtalo en trozos pequeños y vuelve a ponerlo en la sopa.', kosher_type = 'Dairy' where name = 'Slow-Cooked French Onion Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Heat oil in a large pot. Add onions and garlic and sauté over high heat until the onions are translucent and soft, about 8–10 minutes. | Add zucchini, lower the heat to medium, and add the water. Place the chicken in a soup bag and add it to the soup. Add the seasonings and let cook for 1 1/2 hours, until the chicken is soft. | Remove the chicken bag from the soup. Using an immersion blender, blend the soup until smooth. Slowly add the cornstarch mixture to thicken the soup. | Remove the chicken from the bone, cut it into bite-sized pieces, and add it back to the soup.', instructions_es = 'Precalienta el horno a 400°F. | Corta las mini baguettes a lo largo. Una por una, pasa una brocheta por el centro para que pueda apoyarse sobre ambos bordes del bowl. | Coloca los panes preparados en una bandeja para horno. | Mezcla el perejil, el ajo, el aceite de oliva y la sal en un bowl pequeño. | Divide esta mezcla entre las 8 mitades de pan y úntala bien por encima. | Hornea de 10 a 15 minutos, hasta que estén apenas dorados en los bordes y aromáticos. | Colócalos con cuidado sobre cualquier sopa que combine bien con este pan. | Nota | Puede prepararse con anticipación, horneando un poco menos, congelando y luego recalentando hasta que quede crocante.', kosher_type = 'Meat' where name = 'Cream of Chicken Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 400°F. | Cut the mini baguettes lengthwise. One at a time, and making sure to stay centered, thread a skewer through the baguette so it can lay flat across the bowl. Place the prepared baguettes on a baking sheet. | Mix parsley, garlic, olive oil, and salt in a small bowl. Divide this mixture between the 8 baguette halves, spreading it all over the bread. | Bake for 10–15 minutes, until browned a bit at the edges and fragrant. | Carefully place over any soup that works well with the bread. | Notes | To prepare in advance, underbake slightly, freeze, then thaw and rewarm until crisp and fragrant.', instructions_es = 'Precalienta el horno a 350°F. | Con un cuchillo afilado, corta 3 tiras largas, de aproximadamente 1 1/4 pulgadas de ancho, desde el centro de cada wrap. | Rocía las tiras con spray antiadherente y hornéalas unos 8 minutos, hasta que estén doradas y tipo cracker. | Al servir, coloca una tira crujiente sobre cada sopa y termina con la decoración que prefieras. | Nota | Pueden prepararse con anticipación y guardarse congelados o en un recipiente hermético.', kosher_type = 'Parve' where name = 'Parsley Garlic Bread on a Skewer' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. | Using a sharp knife, cut out 3 long sticks (about 1 1/4 inches wide) at the center of each wrap. Cut out as many as you need. | Spray the sticks with cooking spray and bake for about 8 minutes, or until browned and cracker-like. | When plating, place one cracker on each soup and top with garnish of your choice. | Notes | These can be prepared in advance and either frozen or stored in an airtight container.', instructions_es = 'En el fondo del frasco, mezcla la sal, la pasta de tamarindo, el jugo de lima, el aceite de sésamo, el caldo, el ajo, el jengibre y la salsa de soja. | Agrega las verduras en ese orden. Si usas otras verduras, empieza abajo con las que no se pongan blandas fácilmente. | Tapa bien y guarda en la heladera hasta el momento de usar. | Cuando vayas a comerlo, llena el frasco con agua hirviendo. | Tapa bien y da vuelta el frasco varias veces para distribuir el sabor. | Déjalo reposar 8 minutos, hasta que las verduras se ablanden y los sabores se mezclen. | Vuelca en un bowl o cómelo directamente del frasco.', kosher_type = 'Parve' where name = 'Elegant Soup Stick' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In the bottom of the jar, combine salt, tamarind paste, lime juice, sesame oil, bouillon, garlic, ginger, and soy sauce. | Add the vegetables in order. If adding other vegetables, make sure to start on the bottom with ones that won’t get soggy. Cover tightly and refrigerate until ready to serve. | When ready to eat, fill the jar with boiling water. Cover tightly and turn the jar up and down a few times to distribute flavor. Let sit for 8 minutes, until the vegetables soften and the flavors blend. | Pour into a bowl, or eat right out of the jar. | Notes | Serves 1 lunch.', instructions_es = 'Precalienta el horno a 400°F y forra una bandeja con papel pergamino. | Mezcla la coliflor con el aceite de oliva, 1 cucharada de sal kosher y 1/2 cucharadita de pimienta negra. Distribúyela en la bandeja y ásala hasta que esté dorada, de 35 a 40 minutos. | Corta el beef fry en tiras muy cortas y finas. Cocínalo en una olla grande a fuego medio-alto, revolviendo de vez en cuando, hasta que esté dorado y crocante, de 10 a 12 minutos. | Retíralo con espumadera, escúrrelo sobre papel absorbente y resérvalo. No descartes la grasa. | Agrega el apio, la cebolla, el ajo y el eneldo a la grasa y cocina de 8 a 10 minutos, revolviendo a veces. | Agrega el jerez y sube el fuego. Cocina hasta que el líquido se reduzca casi por completo, unos 5 minutos. | Agrega la coliflor asada, el caldo, la leche no láctea y las hojas de laurel. Sazona con la cucharada restante de sal y la 1/2 cucharadita restante de pimienta. | Lleva a hervor suave, luego baja el fuego y cocina de 25 a 30 minutos. | Retira las hojas de laurel y licúa la sopa hasta que quede suave. | Sirve con los croutons de beef fry por encima.', kosher_type = 'Meat' where name = 'Vegetarian “Pho” in a Jar (or Bowl)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 400°F. Line a baking sheet with parchment paper. | Toss the cauliflower with the olive oil, 1 tablespoon kosher salt, and 1/2 teaspoon black pepper. Spread on the prepared baking sheet and roast until golden brown, 35–40 minutes. | Slice the beef fry widthwise into very short, narrow strips. Place into a 6-quart pot over medium-high heat and cook, stirring occasionally, until browned and crisp, 10–12 minutes. Remove with a slotted spoon, drain on paper towels, and set aside. Do not discard the rendered fat. | Add the celery, onion, garlic, and dill to the rendered fat and cook for 8–10 minutes, stirring occasionally. Add the sherry and raise the heat. Cook until the liquid is mostly evaporated, about 5 minutes. | Add the roasted cauliflower, broth, nondairy milk, and bay leaves. Season with the remaining 1 tablespoon kosher salt and 1/2 teaspoon black pepper. Bring to a low boil, then reduce heat and simmer for 25–30 minutes. | Remove and discard bay leaves. Using an immersion blender, purée the soup until smooth. Garnish with the beef-fry croutons.', instructions_es = 'Precalienta el horno a 375°F. | Pincela dos fuentes grandes y bajas con 1 cucharada de aceite de oliva. | Acomoda los tomates, los pimientos, el zucchini y la berenjena en una sola capa, con el lado cortado hacia abajo. | Distribuye alrededor el ajo y la cebolla, rocía con el resto del aceite y espolvorea el tomillo, el orégano, sal y pimienta. | Hornea destapado de 30 a 35 minutos, hasta que todo esté blando y dorado. | Cuando se enfríe un poco, retira la piel de los pimientos y los tomates y saca la pulpa de la berenjena. | Coloca las verduras en un bowl y licúa con batidora de inmersión hasta que quede con textura algo gruesa, como salsa, no completamente lisa. | Pasa la mezcla a una olla, agrega el caldo y cocina a fuego suave de 20 a 30 minutos. | Incorpora la leche no láctea y cocina hasta que esté bien caliente. Ajusta con sal y pimienta. | Sirve caliente con albahaca fresca por encima.', kosher_type = 'Dairy' where name = 'Cauliflower Soup with Beef-Fry Croutons' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 375°F. | Brush two large, shallow baking dishes with 1 tablespoon olive oil. Arrange tomatoes, peppers, zucchini, and eggplant in a single layer, cut sides down. Sprinkle garlic and onion around the vegetables and drizzle with the remaining oil. Sprinkle with thyme and oregano and season with salt and pepper to taste. | Place in oven and roast, uncovered, for 30–35 minutes, or until soft and browned. Once cooled, scrape out the eggplant flesh and remove skin from peppers and tomatoes. | Add the vegetables to a bowl and use an immersion blender to purée the eggplant, peppers, zucchini, tomatoes, garlic, and onion until chunky like a salsa, not completely smooth. | In a soup pot, combine the chunky vegetable mixture with the broth and simmer for 20–30 minutes. Stir in the nondairy milk and simmer until hot. Add salt and pepper to taste. | Serve warm, topped with shredded basil. | Notes | Serves 6.', instructions_es = 'Saltea las cebollas hasta que estén transparentes. | Agrega el puerro, el brócoli, la mezcla de sopa de pollo, la sal y la pimienta. | Cocina hasta que todo esté blando. | Licúa hasta obtener una crema suave. | Nota | Algunas cantidades no aparecían especificadas en el mensaje original.', kosher_type = 'Dairy' where name = 'Roasted Mediterranean Vegetable Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté the onions until clear. | Add the leek, broccoli florets, chicken soup mix, salt, and pepper. | Cook until soft. | Blend until smooth. | Notes | Some quantities were not specified in the message and are preserved as written.', instructions_es = 'Saltea el ajo en un poco de aceite de oliva suave. | Agrega la cebolla, el zucchini, la calabaza amarilla y la zanahoria y cocina hasta que empiecen a ablandarse. | Agrega la coliflor congelada. | Sazona con pimienta negra, sal, pimentón y mezcla de sopa de pollo. | Llena la olla con agua y cocina hasta que las verduras estén tiernas. | Haz una olla grande y congela el resto.', kosher_type = 'Meat' where name = 'Cream of Broccoli Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté the garlic in a little light olive oil. | Add the onions, zucchini, yellow squash, and carrots and cook until beginning to soften. | Add the frozen cauliflower florets. | Season with black pepper, salt, paprika, and chicken soup mix. | Fill the pot with water and cook until the vegetables are tender. | Make a big pot and freeze the rest.', instructions_es = 'Saltea la cebolla en aceite. Agrega el zucchini y la zanahoria y cocina hasta que estén blandos. | Agrega el perejil, el eneldo, la harina, el agua hirviendo, la mezcla de sopa de pollo, la sal y la pimienta. | Cocina a fuego bajo durante 1 hora. | Licúa hasta que quede suave.', kosher_type = 'Meat' where name = 'Chunky Hearty Vegetable Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté the onion in oil. Add the zucchini and carrot and sauté until soft. | Add the parsley, dill, flour, boiling water, chicken soup mix, salt, and pepper. | Simmer for 1 hour. | Blend until smooth.', instructions_es = '', kosher_type = 'Meat' where name = 'Zucchini Soup (Daniella)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = 'Asa las verduras con anticipación y déjalas enfriar. La receta indica que se pueden preparar antes y guardar en la heladera. | Licúa todos los ingredientes del aderezo en un procesador hasta que quede suave. | Cuando vayas a servir, mezcla las verduras asadas y las hojas verdes con el aderezo. | Nota | La imagen incluía una receta completa para el aderezo y una idea general de cómo armar la ensalada, pero no cantidades exactas de cada verdura.', kosher_type = 'Parve' where name = 'Cauliflower Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Prepare the marinade in a bowl. Whisk together the soy sauce, oil, sesame oil, honey, garlic, clementine juice, red pepper flakes, salt, and black pepper. | Place the chicken in a zip-top bag with the marinade and shake to mix. Seal and leave overnight in the refrigerator, or for at least 6 hours. | Prepare the vinaigrette in a jar or cruet. Combine all dressing ingredients and shake until well combined. | Remove the chicken from the marinade and grill or broil for 6-8 minutes per side. | In a large bowl, combine the baby arugula, red onion, endive, pomegranate seeds, sunflower seeds, and slivered almonds. Toss with the vinaigrette. | Arrange the clementine slices either on top of the salad or on the side, and sprinkle them with pomegranate seeds and black sesame seeds. | Serve with the chicken. | Notes | Serves 6.', instructions_es = 'Bate todos los ingredientes del aderezo hasta que quede liso. La mantequilla de maní puede necesitar un poco más de batido para integrarse por completo. | Mezcla todos los ingredientes de la ensalada en un bowl, o colócalos en capas si quieres una presentación más linda. | Mezcla con el aderezo justo antes de servir y termina con las coberturas que prefieras. | Nota | Rinde de 4 a 6 porciones.', kosher_type = 'Parve' where name = 'Clementine Glazed Chicken and Baby Arugula Salad with Balsamic-Soy Vinaigrette' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 350 F. In a small bowl, coat the walnuts with the maple syrup and spread in a single layer on a baking sheet. | Bake for 10 minutes, or until fragrant. Allow to cool. | To prepare the dressing, place all dressing ingredients in a small jar or cruet and shake well to combine. | In a large salad bowl, combine the walnuts with the salad ingredients. Add the dressing and toss to combine. | Serve immediately. | Notes | Serves 6-8.', instructions_es = '', kosher_type = 'Parve' where name = 'Arugula and Endive Salad with Maple Walnuts' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = 'Prepara la marinada mezclando la salsa de soja, el aceite, el aceite de sésamo, la miel, el ajo, el jugo de clementina, las hojuelas de ají, la sal y la pimienta. | Coloca el pollo en una bolsa con cierre junto con la marinada y mezcla bien. Guarda en la heladera toda la noche, o por al menos 6 horas. | Prepara la vinagreta en un frasco o recipiente con tapa. Mezcla todos los ingredientes y agita hasta integrar. | Retira el pollo de la marinada y ásalo o cocínalo bajo el grill durante 6 a 8 minutos por lado. | En un bowl grande, mezcla la rúcula, la cebolla morada, la endivia, las semillas de granada, las semillas de girasol y las almendras laminadas. Agrega la vinagreta y mezcla. | Acomoda las rodajas de clementina encima o al costado de la ensalada y espolvoréalas con semillas de granada y sésamo negro. | Sirve junto con el pollo.', kosher_type = 'Parve' where name = 'Classic Cobb Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Salt the cucumbers and let sit for 1/2 hour. | Notes | The handwritten source note only included the brief direction above.', instructions_es = 'Precalienta el horno a 350°F. En un bowl pequeño, mezcla las nueces con el jarabe de maple y extiéndelas en una sola capa sobre una bandeja. | Hornéalas durante 10 minutos, o hasta que estén aromáticas. Déjalas enfriar. | Para preparar el aderezo, coloca todos los ingredientes en un frasco o recipiente y agita bien para mezclar. | En un bowl grande, mezcla las nueces con los ingredientes de la ensalada. Agrega el aderezo y mezcla para integrar. | Sirve de inmediato.', kosher_type = 'Parve' where name = 'Cucumber Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Slice pastrami and saute in a small amount of oil until it starts to get crispy. Do not let it dry out. Remove from the heat and cool. | Store in a container in the refrigerator until ready to use. | For the dressing, blend onion and sugar well using a food processor. Add vinegar and salt. | Slowly add the oil and blend for a few minutes until the color starts to lighten and the dressing becomes creamy. | Store the dressing in a container in the refrigerator for up to a week. | To assemble, place lettuce, apple, and pomegranate seeds in a bowl. Top with pastrami and drizzle with dressing. Toss and serve. | Notes | Yield: 8-10 servings. | Note from source: you can seed the pomegranate in advance, but it is best to cut and prep the apple and lettuce right before serving. | Note from source: if you do not use vinegar on Rosh Hashanah, this salad will still be delicious with any salad dressing you are able to use.', instructions_es = '', kosher_type = 'Parve' where name = 'Pastrami, Apple & Pomegranate Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = 'Sala los pepinos y déjalos reposar durante 1/2 hora. | Nota | La nota escrita a mano solo incluía esta indicación breve.', kosher_type = 'Parve' where name = 'Mushroom Romaine Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a large bowl, combine greens, mango, oranges, and cucumbers. | Whisk the dressing ingredients separately and toss with the salad, or simply drizzle all the dressing ingredients over the greens and toss. | Top with Craisins and almonds and enjoy.', instructions_es = 'Corta el pastrami en tiras y saltéalo en un poco de aceite hasta que comience a quedar crujiente. No lo dejes secarse. Retíralo del fuego y deja enfriar. | Guárdalo en un recipiente en la heladera hasta el momento de usar. | Para el aderezo, procesa muy bien la cebolla con el azúcar. Agrega el vinagre y la sal. | Incorpora lentamente el aceite y procesa durante unos minutos hasta que el color se aclare y el aderezo quede cremoso. | Guarda el aderezo en la heladera hasta por una semana. | Para armar la ensalada, coloca la lechuga, la manzana y las semillas de granada en un bowl. Agrega el pastrami por encima y rocía con el aderezo. Mezcla y sirve. | Notas | La receta original indica que puedes desgranar la granada con anticipación, pero conviene cortar la manzana y preparar la lechuga justo antes de servir. | También decía que si no usas vinagre en Rosh Hashaná, esta ensalada igual queda rica con cualquier aderezo permitido que uses.', kosher_type = 'Parve' where name = 'Silan and Lime Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = '', kosher_type = 'Parve' where name = 'Purple Cabbage Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix all dressing ingredients together before mixing over the vegetables. | This salad should last almost a week in the fridge. | Feel free to make it your own by adding in radishes or chickpeas or whatever you are in the mood for.', instructions_es = 'En un bowl grande, mezcla las hojas verdes, el mango, la naranja y los pepinos. | Bate aparte los ingredientes del aderezo y mézclalos con la ensalada, o simplemente rocíalos directamente sobre las hojas y mezcla. | Termina con los craisins y las almendras y sirve.', kosher_type = 'Parve' where name = 'Not Your Typical Cucumber Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a large bowl, toss together arugula, spinach, apple, walnuts, and cranberries. | The source image shows the beginning of step 2: prepare the dressing by whisking together the vinegar, orange zest, orange juice, mustard, maple syrup, salt, and pepper. The remainder of the step is cut off in the screenshot. | Notes | The source image includes a serving suggestion: add roasted pastrami strips on top.', instructions_es = '', kosher_type = 'Parve' where name = 'Light N Springy Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the oven to 350 F. | Wash and dry the potatoes. Leaving the peels on, cut each potato in half and place in a baking pan. | Sprinkle the potatoes with oil, salt, and pepper. Bake, covered, until cooked through, about 1 hour. | In a large bowl, combine the baked potatoes with the mayonnaise, mustard, lemon juice, Worcestershire sauce, gherkins, and dill. | Season with salt and pepper. Serve warm, at room temperature, or cold. | Notes | Serves 4-6.', instructions_es = 'Mezcla todos los ingredientes del aderezo antes de agregarlo a las verduras. | Esta ensalada debería durar casi una semana en la heladera. | Puedes adaptarla a tu gusto agregando rabanitos, garbanzos o lo que tengas ganas.', kosher_type = 'Parve' where name = 'Baby Red Potato Salad with Caesar Dill Dressing' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Massage the kale with the listed kale-prep ingredients and set aside. | The remaining directions are cut off in the source image. | Notes | The source image notes that if checked kale is unavailable, baby greens can be used.', instructions_es = 'En un bowl grande, mezcla la rúcula, la espinaca, la manzana, las nueces y los arándanos. | La imagen mostraba el comienzo del paso 2: preparar el aderezo batiendo el vinagre, la ralladura de naranja, el jugo de naranja, la mostaza, el maple, la sal y la pimienta. El resto del paso estaba cortado. | Notas | La imagen sugería agregar tiras de pastrami asado por encima al servir.', kosher_type = 'Parve' where name = 'Kale Quinoa Salad (Raizys Fave Urbana Salad)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = 'Precalienta el horno a 350°F. | Lava y seca las papas. Sin pelarlas, corta cada una por la mitad y colócalas en una fuente para horno. | Rocía las papas con aceite, sal y pimienta. Hornéalas tapadas hasta que estén bien cocidas, aproximadamente 1 hora. | En un bowl grande, mezcla las papas cocidas con la mayonesa, la mostaza, el jugo de limón, la salsa Worcestershire, los pepinillos y el eneldo. | Ajusta con sal y pimienta. Sirve tibia, a temperatura ambiente o fría.', kosher_type = 'Parve' where name = 'Broccoli Slaw with Craisins, Red Onion, and Cashews' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Whisk together all dressing ingredients until smooth. Peanut butter may take a little extra whisking to fully incorporate. | Combine all salad ingredients in a bowl, or layer them in a terrine-style bowl for presentation. | Toss with dressing when ready to serve and top with any desired toppings.', instructions_es = '', kosher_type = 'Dairy' where name = 'Soba Spring Noodle Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Whisk together and toss with salad. | Notes | The screenshot did not give an exact amount for the garlic salt.', instructions_es = '', kosher_type = 'Parve' where name = 'Simple Lemon Oil Dressing' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine lettuce, mango, pistachios, tomatoes, dried cranberries, and onion in a large bowl. | Place dressing ingredients in a small jar and shake, or blend to combine. | Toss dressing with salad and serve.', instructions_es = 'Mezcla la lechuga, el mango, los pistachos, los tomates, los arándanos secos y la cebolla en un bowl grande. | Coloca los ingredientes del aderezo en un frasco pequeño y agita, o licúa para unir. | Mezcla la ensalada con el aderezo y sirve.', kosher_type = 'Parve' where name = 'Sium Hashas Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine mayonnaise, lemon juice, salt, and sugar until smooth. | Use immediately or refrigerate until needed.', instructions_es = 'Mezcla la mayonesa, el jugo de limón, la sal y el azúcar hasta que quede suave. | Úsalo enseguida o guárdalo en la heladera hasta necesitarlo.', kosher_type = 'Parve' where name = 'Basic Salad Dressing' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Slice the cucumbers and let them sit for about 1/2 hour. | Prepare the dressing with the water, vinegar, sugar, and salt. | Add the cucumber, onion, and optional carrot to the dressing. | Chill before serving.', instructions_es = 'Corta los pepinos y déjalos reposar aproximadamente 1/2 hora. | Prepara el aderezo con el agua, el vinagre, el azúcar y la sal. | Agrega el pepino, la cebolla y la zanahoria opcional al aderezo. | Enfría antes de servir.', kosher_type = 'Parve' where name = 'Cucumber Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a medium bowl, combine quinoa, cucumber, carrot, tomatoes, avocado, chickpeas, feta cheese, and scallions. | In a small bowl, whisk together the dressing ingredients. | Toss the salad with dressing and garnish with sunflower seeds before serving.', instructions_es = 'En un bowl mediano, mezcla la quinoa, el pepino, la zanahoria, los tomates, el aguacate, los garbanzos, el queso feta y los cebollines. | En un bowl pequeño, bate todos los ingredientes del aderezo. | Mezcla la ensalada con el aderezo y termina con semillas de girasol antes de servir.', kosher_type = 'Dairy' where name = 'Mediterranean Quinoa Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Bring water to a boil and dip the tomatoes in for a few minutes. | Transfer tomatoes to cold water and peel them. | Pulse the tomatoes and onions in a food processor so the mixture is not too fine and not too chunky. | Season with salt, oil, and black pepper, tasting until it suits your preference.', instructions_es = 'Hierve agua y sumerge los tomates unos minutos. | Pásalos a agua fría y pélalos. | Pulsa los tomates y las cebollas en un procesador para que la mezcla no quede ni demasiado fina ni demasiado gruesa. | Sazona con sal, aceite y pimienta negra, probando hasta que quede a tu gusto.', kosher_type = 'Meat' where name = 'Tomato Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. | Place pastrami in a roasting pan with water to cover. Cover tightly and place in the oven for 1 1/2 to 2 hours, until very soft. | When cool enough to handle, but still warm, shred the pastrami. Cover and set aside. | Place all dressing ingredients in a tall container and blend. | Combine the vegetables in a salad bowl. | Pour dressing over the salad vegetables and toss. Place shredded pastrami on top.', instructions_es = 'Precalienta el horno a 350°F. | Coloca el pastrami en una fuente para horno con agua suficiente para cubrirlo. Tapa bien y hornéalo de 1 1/2 a 2 horas, hasta que esté muy blando. | Cuando esté lo suficientemente frío para manipularlo, pero todavía tibio, desmenúzalo. Tápalo y resérvalo. | Coloca todos los ingredientes del aderezo en un recipiente alto y licúa. | Mezcla las verduras en un bowl para ensalada. | Vierte el aderezo sobre las verduras y mezcla. Coloca el pastrami desmenuzado por encima.', kosher_type = 'Meat' where name = 'Shredded Pastrami Over Leafy Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F (175°C). | Combine apples, sugar, lemon juice, and cinnamon. Place in the bottom of a 9x13-inch baking pan or two 9-inch round pans. | Top with sliced strawberries. | With a fork, mix together the crumble ingredients. Crumble with your fingers and arrange on top of the strawberries. | Bake uncovered for 1 to 1 1/2 hours, or until done.', instructions_es = 'Precalienta el horno a 350°F (175°C). | Mezcla las manzanas con el azúcar, el jugo de limón y la canela. Colócalas en el fondo de una fuente de 9x13 pulgadas o en dos moldes redondos de 9 pulgadas. | Cubre con las fresas en rodajas. | Con un tenedor, mezcla los ingredientes del crumble. Deshaz la mezcla con los dedos y repártela sobre las fresas. | Hornea destapado de 1 a 1 1/2 horas, o hasta que esté listo.', kosher_type = 'Parve' where name = 'Apple Strawberry Crumble' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Blend all ingredients together in a food processor. | Use with roasted vegetables and greens.', instructions_es = 'Licúa todos los ingredientes en un procesador de alimentos. | Úsalo con verduras asadas y hojas verdes. | Nota | Si el vino no es dulce, agrega un poco de azúcar.', kosher_type = 'Parve' where name = 'White Wine Dressing for Roasted Veggie Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté onions in oil for 7 to 8 minutes until clear and soft. | Add the flour or potato starch, stirring well. | Add the mayonnaise and chicken stock. Cook 2 to 3 minutes until the sauce thickens. Set aside. | Peel and slice the potatoes into 1/4-inch-thick slices. | Pour 3 to 4 ladles of sauce on the bottom of a 9x13-inch pan. | Spread a layer of potatoes, then sauce, then another layer of potatoes, ending with sauce on top. | Sprinkle with salt, pepper, and paprika. | Bake at 350°F for 1 to 1 1/2 hours, or until ready.', instructions_es = 'Saltea las cebollas en el aceite durante 7 a 8 minutos, hasta que estén transparentes y blandas. | Agrega la harina o fécula de papa, revolviendo bien. | Añade la mayonesa y el caldo de pollo. Cocina 2 a 3 minutos hasta que la salsa espese. Reserva. | Pela y corta las papas en rodajas de 1/4 de pulgada de grosor. | Pon 3 a 4 cucharones de salsa en el fondo de una fuente de 9x13 pulgadas. | Haz una capa de papas, luego salsa, luego otra capa de papas, terminando con salsa arriba. | Espolvorea con sal, pimienta y pimentón. | Hornea a 350°F durante 1 a 1 1/2 horas, o hasta que esté listo.', kosher_type = 'Meat' where name = 'Scalloped Potatoes - Pareve' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a medium saucepan over medium heat, sauté the onions and pastrami in the fat, stirring frequently, until the onions are caramelized and the pastrami is browned in spots. | Add potato starch and stir until the onion and pastrami mixture is evenly coated. | Add mayonnaise, chicken stock, salt, and pepper; stir until the mixture is smooth and thickened. | Preheat oven to 350°F. | Peel and slice potatoes crosswise into very thin circles. Rinse well with cold water. | Pour some sauce into a 9x13-inch baking dish. Arrange a layer of potato slices over the sauce, then more sauce, and continue the pattern until you have about 5 to 6 layers. Cover tightly with foil. | Bake for 30 minutes, then uncover and cook for another hour, or until crispy.', instructions_es = 'En una cacerola mediana a fuego medio, saltea las cebollas y el pastrami en la grasa, revolviendo seguido, hasta que las cebollas estén caramelizadas y el pastrami se dore en algunos puntos. | Agrega la fécula de papa y mezcla hasta que las cebollas y el pastrami queden bien cubiertos. | Añade la mayonesa, el caldo de pollo, la sal y la pimienta; revuelve hasta que la mezcla esté suave y espese. | Precalienta el horno a 350°F. | Pela las papas y córtalas en rodajas muy finas. Enjuágalas bien con agua fría. | Vierte un poco de salsa en una fuente para horno de 9x13 pulgadas. Acomoda una capa de papas sobre la salsa, luego más salsa, y continúa así hasta tener unas 5 o 6 capas. Cubre bien con aluminio. | Hornea 30 minutos, luego destapa y cocina otra hora, o hasta que esté crocante.', kosher_type = 'Meat' where name = 'Scalloped Potatoes with Pastrami' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a pot, sauté the onions with the margarine, brown sugar, and red wine vinegar until lightly golden. | Sprinkle the potato starch over the onions while stirring. | Add the water and soup mix and let it simmer until it thickens, then turn off the heat. Taste and add more salt if needed. | Slice the potatoes thinly. | Grease a baking dish or 9x13 pan and start layering sauce, potatoes, sauce, potatoes, ending with sauce on top. | Sprinkle with paprika and black pepper. | Bake at 350°F for about 1 1/2 hours.', instructions_es = 'En una olla, saltea las cebollas con la margarina, el azúcar morena y el vinagre de vino tinto hasta que estén apenas doradas. | Espolvorea la fécula de papa sobre las cebollas mientras revuelves. | Agrega el agua y la mezcla para sopa, y deja hervir suavemente hasta que espese. Luego apaga el fuego. Prueba y agrega más sal si hace falta. | Corta las papas bien finas. | Engrasa una fuente o molde de 9x13 pulgadas y comienza a hacer capas de salsa, papas, salsa, papas, terminando con salsa arriba. | Espolvorea con pimentón y pimienta negra. | Hornea a 350°F durante aproximadamente 1 1/2 horas.', kosher_type = 'Parve' where name = 'Scalloped Potatoes (Instagram Version)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'The provided image only shows the topping ingredients and does not include the rest of the recipe.', instructions_es = '', kosher_type = 'Parve' where name = 'Apple Kugel Topping (Partial)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Bring a large pot of salted water to a boil. Cook green beans for about 5 to 7 minutes; drain. Run ice-cold water over the green beans immediately to stop the cooking. Drain again. | Place all dressing ingredients in a food processor fitted with the steel blade attachment. Process on high for about 1 minute. | When ready to serve, place green beans, mango, dried cranberries, and almonds in a large bowl. Drizzle dressing over and toss well. | Notes | Yield: approximately 6 servings. | Note: This dressing can be made ahead of time and kept in an airtight container in the refrigerator.', instructions_es = 'Hierve una olla grande con agua salada. Cocina los ejotes unos 5 a 7 minutos; escúrrelos. Pásales agua helada enseguida para cortar la cocción. Vuelve a escurrir. | Coloca todos los ingredientes del aderezo en un procesador con cuchilla de metal. Procesa a máxima velocidad durante aproximadamente 1 minuto. | Cuando vayas a servir, coloca los ejotes, el mango, los arándanos secos y las almendras en un bowl grande. Rocía con el aderezo y mezcla bien.', kosher_type = 'Parve' where name = 'Colorful Green Bean Salad with Creamy Garlic Dressing' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Whisk together all dressing ingredients until smooth. | Combine all salad ingredients in a bowl, or layer in a terrine-style bowl if desired. | Toss with dressing when ready to serve and top with desired toppings. | Notes | Yield: 4 to 6 servings.', instructions_es = 'Bate todos los ingredientes del aderezo hasta que quede suave. | Mezcla todos los ingredientes de la ensalada en un bowl, o acomódalos en capas si deseas. | Agrega el aderezo justo antes de servir y termina con las coberturas que prefieras.', kosher_type = 'Dairy' where name = 'Soba Spring Noodle Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine all salad ingredients. | Dress with olive oil, lemon juice, salt, black pepper, and cumin. | Toss and refrigerate overnight so the dressing can soak in. | Leave out for about 20 minutes before serving and toss again. | Notes | A commenter suggested adding a little red wine vinegar and honey, if desired.', instructions_es = 'Mezcla todos los ingredientes de la ensalada. | Aliña con aceite de oliva, jugo de limón, sal, pimienta negra y comino. | Mezcla y refrigera toda la noche para que el aderezo se absorba. | Déjala reposar unos 20 minutos fuera de la heladera antes de servir y vuelve a mezclar.', kosher_type = 'Parve' where name = 'Bean, Corn, and Cilantro Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Using fresh string beans, wash and snip off the ends. | Place on a baking sheet, toss with the oil, and mix. | Scatter over the almonds, garlic, and salt. | Bake at 400°F for 15 to 20 minutes, until crunchy. If you like them softer, add a little more oil. | This is also very good prepared in a wok as a stir-fry. | Notes | Serving/yield: 6.', instructions_es = 'Lava los ejotes frescos y córtales las puntas. | Colócalos en una bandeja para horno, mézclalos con el aceite y revuelve. | Esparce por encima las almendras, el ajo y la sal. | Hornea a 400°F durante 15 a 20 minutos, hasta que queden crujientes. Si te gustan más suaves, agrega un poco más de aceite. | También quedan muy ricos preparados en wok como salteado.', kosher_type = 'Parve' where name = 'Garlic Roasted String Beans' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Method 1: Oven-Baked Rice — Preheat oven to 350°F (175°C). In an ovenproof dish, mix the rice, oil, water, and salt. Cover tightly with foil and bake for 30 minutes. Remove from the oven and let stand for 10 minutes. Fluff with a fork and serve. | Method 2: Stovetop — Heat a saucepan over medium heat. Add the oil and rice. Stir for 1 to 2 minutes until the rice is well-coated. Add the salt and boiling water. Scrape any rice from the bottom of the pot. Bring to a boil, cover, and reduce to a simmer for 15 to 20 minutes. Let stand for 10 minutes. Fluff with a fork and serve. | Notes | The printed note says the oven-baked method yields rice that is fluffier yet a bit mushy, while the stovetop rice has more distinct grains and is chewy, fluffy, and sticky enough. | The original article notes a 1:1.5 rice-to-water ratio for white rice.', instructions_es = '', kosher_type = 'Parve' where name = 'Get Rice Right' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. | Slice off the top of the garlic head and drizzle with olive oil. Seal in a tin foil pouch and bake for 1 hour. Let cool and squeeze out the roasted cloves. | Bring a pot of water to a boil. Add cauliflower and cook for 10 minutes. Strain well. | Place hot cauliflower in a blender and pulse. Once it is broken down, add roasted garlic, dairy-free butter, and salt. Keep pulsing until smooth and creamy. | Remove from blender, add chives, and serve. | Notes | Yield: 4 servings.', instructions_es = 'Precalienta el horno a 350°F. | Corta la parte superior de la cabeza de ajo y rocíala con aceite de oliva. Ciérrala en un paquetito de aluminio y hornéala durante 1 hora. Deja enfriar y exprime los dientes asados. | Lleva una olla con agua a hervor. Agrega la coliflor y cocina durante 10 minutos. Escurre bien. | Coloca la coliflor caliente en una licuadora y pulsa varias veces. Cuando esté deshecha, agrega el ajo asado, la mantequilla vegetal y la sal. Sigue procesando hasta que quede suave y cremosa. | Retira de la licuadora, agrega el cebollín y sirve.', kosher_type = 'Dairy' where name = 'Garlic and Chive Cauliflower Mash' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Boil potatoes in salted water until soft. Drain and mash. Add margarine and mix. Allow to cool. | Preheat oven to 350°F (180°C). | When potatoes are cool, add the remaining knish ingredients. If desired, blend using a stick blender for a smoother texture. | Spoon into muffin cups and sprinkle with sesame seeds. Bake for 45 minutes, or less if using mini muffin cups. | For the topping, sauté onion until golden. Add pastrami and beef fry and sauté 5 minutes longer. | Add the remaining topping ingredients and allow the sugar to melt. Continue to simmer on low another 3 to 5 minutes. | Rewarm before serving and spoon over doughless knishes. | Notes | Yields approximately 12 knishes.', instructions_es = 'Hierve las papas en agua con sal hasta que estén blandas. Escurre y haz puré. Agrega la margarina y mezcla. Deja enfriar. | Precalienta el horno a 350°F (180°C). | Cuando las papas estén frías, agrega el resto de los ingredientes de los knishes. Si deseas una textura más suave, puedes usar batidora de inmersión. | Coloca la mezcla en moldes para muffins y espolvorea con semillas de sésamo. Hornea 45 minutos, o menos si usas moldes mini. | Para la cobertura, saltea la cebolla hasta que esté dorada. Agrega el pastrami y el beef fry y saltea 5 minutos más. | Añade el resto de los ingredientes de la cobertura y deja que el azúcar se derrita. Cocina a fuego bajo otros 3 a 5 minutos. | Vuelve a calentar antes de servir y colócala sobre los knishes.', kosher_type = 'Meat' where name = 'Seasoned Doughless Potato Knishes' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Use the food processor S blade to process 4 onions until very mushy, then change to the E blade. | In a bowl, put eggs and oil together, then add potatoes and salt. | Preheat oven to 350°F. Grease a 9x13 pan with cooking spray and place the pan in the oven for a few minutes. | Pour the mixture into the hot pan and bake uncovered for 2 hours, until browned. | To reheat overnight, cover twice and place water on the bottom. Warm on 200°F. | Notes | This recipe was handwritten and some wording was hard to read; this is a careful transcription of the visible instructions.', instructions_es = 'Usa la cuchilla S del procesador para procesar 4 cebollas hasta que queden muy blandas, luego cambia a la cuchilla E. | En un bowl, mezcla los huevos y el aceite, luego agrega las papas y la sal. | Precalienta el horno a 350°F. Engrasa una fuente de 9x13 con spray antiadherente y colócala unos minutos en el horno. | Vierte la mezcla en la fuente caliente y hornea destapado durante 2 horas, hasta que esté dorado. | Para recalentar toda la noche, cubre dos veces y coloca agua en la parte inferior. Caliéntalo a 200°F.', kosher_type = 'Parve' where name = 'Avis Kugel' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Cook rice according to package directions and set aside. | Meanwhile, sauté garlic and onion in a small amount of oil over low heat until golden. | Add chopped meat and cook until meat is no longer pink and is thoroughly cooked through, about 12 to 15 minutes. Mix constantly, pressing the meat down and breaking it apart as you stir. | Add this mixture to the rice. | Add soy sauce, brown sugar, and cayenne pepper to the pot and mix until well combined. Taste and adjust seasoning if needed. | Stir in a handful of chopped scallions. Garnish with carrot curls. | Notes | Serves 10. | Tip on the clipping: cubed turkey, pastrami, or leftover roast meat can be substituted for the chopped meat.', instructions_es = 'Cocina el arroz según las instrucciones del paquete y resérvalo. | Mientras tanto, saltea el ajo y la cebolla en un poco de aceite a fuego bajo hasta que estén dorados. | Agrega la carne picada y cocina hasta que ya no esté rosada y esté completamente hecha, unos 12 a 15 minutos. Revuelve constantemente, aplastando la carne para deshacerla. | Agrega esta mezcla al arroz. | Añade la salsa de soja, el azúcar morena y la cayena, y mezcla bien. Prueba y ajusta la sazón si hace falta. | Incorpora un puñado de cebollines picados. Decora con zanahoria.', kosher_type = 'Meat' where name = 'Indonesian Rice' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Cook orzo according to package directions. Set aside. | Sauté onion and garlic in a generous amount of oil, about 1/4 cup, then add pastrami cut into small strips. | Add orzo to the pot and drizzle in some soy sauce. Mix well. | Season with a bit of salt and pepper.', instructions_es = 'Cocina el orzo según las instrucciones del paquete. Reserva. | Saltea la cebolla y el ajo en una cantidad generosa de aceite, aproximadamente 1/4 de taza, y luego agrega el pastrami en tiras pequeñas. | Agrega el orzo a la olla y rocía con un poco de salsa de soja. Mezcla bien. | Sazona con un poco de sal y pimienta.', kosher_type = 'Meat' where name = 'Orzo and Pastrami' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Slice the squash lengthwise with peel. Slice mushrooms, then peppers lengthwise into strips. Slice and dice the eggplant into medium-size pieces. Place vegetables on a greased cookie sheet. | Combine olive oil, balsamic vinegar, and salt, and pour over vegetables. | Preheat oven to 350°F and bake for 30 to 40 minutes. | Cook the pasta, rinse, and let stand. | Combine the dressing ingredients with a hand blender or in a container and shake well. Combine vegetables and pasta. | Bake covered at 350°F for 20 minutes. Pour the dressing over the pasta-vegetable mixture and serve.', instructions_es = 'Corta el zucchini a lo largo con la cáscara. Corta los hongos en rodajas y luego los pimientos a lo largo en tiras. Corta la berenjena en trozos medianos. Coloca las verduras en una bandeja engrasada. | Mezcla el aceite de oliva, el vinagre balsámico y la sal, y vierte sobre las verduras. | Precalienta el horno a 350°F y hornea de 30 a 40 minutos. | Cocina la pasta, enjuágala y deja reposar. | Mezcla los ingredientes del aderezo con una batidora de mano o en un recipiente y agita bien. Mezcla las verduras con la pasta. | Hornea tapado a 350°F durante 20 minutos. Vierte el aderezo sobre la mezcla de pasta y verduras y sirve.', kosher_type = 'Parve' where name = 'Oven Roasted Veggies Penne' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 375°F / 190°C. | Slice the eggplants, Roma tomatoes, squash, and zucchini into approximately 1/16-inch rounds and set aside. | Heat 2 tablespoons of olive oil in a 12-inch oven-safe pan. Sauté onions, garlic, and bell peppers until soft. Season with salt and pepper, then add crushed tomatoes. Stir until incorporated. Turn off heat, add basil, and smooth the surface of the sauce. | Arrange the sliced vegetables in alternating patterns on top of the sauce from the outer edge to the inside of the pan. Season with salt and pepper. | Mix the herb seasoning and pour over the vegetables. | Cover the pan with foil and bake for 40 minutes. Uncover and bake an additional 20 minutes until vegetables are soft. | Serve while hot as a main dish or as a side dish. The ratatouille is also excellent the next day.', instructions_es = 'Precalienta el horno a 375°F / 190°C. | Corta las berenjenas, los tomates Roma, la calabaza amarilla y el zucchini en rodajas finas y reserva. | Calienta 2 cucharadas de aceite de oliva en una sartén apta para horno de 12 pulgadas. Saltea la cebolla, el ajo y los pimientos hasta que estén blandos. Sazona con sal y pimienta, agrega los tomates triturados, mezcla bien, apaga el fuego, agrega la albahaca y empareja la superficie. | Acomoda las verduras en rodajas alternando los colores, desde el borde hacia el centro de la sartén. Sazona con sal y pimienta. | Mezcla los ingredientes del sazonador de hierbas y vierte sobre las verduras. | Cubre con aluminio y hornea 40 minutos. Destapa y hornea 20 minutos más, hasta que las verduras estén blandas. | Sirve caliente como plato principal o como acompañamiento. También queda muy bien al día siguiente.', kosher_type = 'Parve' where name = 'Baked Ratatouille' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Put sliced fruit on a greased cookie sheet. | Dry overnight in a 180°F oven for about 8 hours. | Notes | The image caption described this as an easy, healthy idea.', instructions_es = 'Coloca la fruta en rodajas sobre una bandeja engrasada. | Sécala toda la noche en un horno a 180°F durante unas 8 horas.', kosher_type = 'Parve' where name = 'Dried Fruit' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'For the navel pastrami: place the navel pastrami with the vacuum bag in a pan and cover with water. Cover the pan tightly with foil. Bake at 225°F for about 8 to 13 hours, best overnight. | Once cooked, cut open the bag and discard any liquid. Using two forks, pull the meat into shreds. | To assemble: place one pita square on each serving. Smear with a generous tablespoon of barbecue sauce. | Top with about half a handful of arugula and then pastrami. | If using mushrooms or onions, add a couple here. | Generously drizzle each pita with Caesar dressing and serve. | Notes | Yields: 4 servings.', instructions_es = 'Para el navel pastrami: coloca el pastrami con la bolsa al vacío dentro de una fuente y cúbrelo con agua. Tapa bien con aluminio. Hornea a 225°F durante 8 a 13 horas, idealmente toda la noche. | Una vez cocido, abre la bolsa y desecha el líquido. Desmenuza la carne con dos tenedores. | Para armar: coloca un cuadrado de pita en cada porción. Unta con una cucharada generosa de salsa barbecue. | Agrega aproximadamente medio puñado de rúcula y luego el pastrami. | Si usas champiñones o cebollas, agrega un poco ahora. | Rocía generosamente cada pita con aderezo Caesar y sirve.', kosher_type = 'Meat' where name = 'Navel Pastrami Personal Pies' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Prepare the quinoa according to package directions using the broth or water and soup mix. | Preheat the oven to broil. Line a baking sheet with parchment and coat with cooking spray. | Slice peppers lengthwise, remove seeds, and cut each pepper into about 1-inch strips. Cut the eggplant and zucchini into 1-inch chunks. Quarter each onion round. Add vegetables to the prepared quinoa. | Spread vegetables on the baking sheet. Brush or drizzle with oil and season with salt and pepper. | Place baking sheet on the middle shelf and broil for 10 minutes. Turn the vegetables and broil 5 more minutes, or until roasted. Let cool. | Whisk together all dressing ingredients. | Pour dressing over quinoa and roasted vegetables and toss before serving. | Notes | This was carefully reconstructed from the uploaded page; a few words were partially obscured in the photo.', instructions_es = 'Prepara la quinoa según las instrucciones del paquete usando el caldo o agua junto con la mezcla para sopa. | Precalienta el horno en función broil. Forra una bandeja con papel pergamino y rocíala con spray antiadherente. | Corta los pimientos a lo largo, retira las semillas y luego córtalos en tiras de aproximadamente 1 pulgada. Corta la berenjena y el zucchini en trozos de 1 pulgada. Corta cada gajo de cebolla. | Distribuye las verduras en la bandeja. Pincélalas o rocíalas con aceite y sazona con sal y pimienta. | Coloca la bandeja en la rejilla del medio y cocina 10 minutos. Da vuelta las verduras y cocina 5 minutos más, o hasta que estén asadas. Deja enfriar. | Bate todos los ingredientes del aderezo. | Vierte el aderezo sobre la quinoa y las verduras asadas y mezcla antes de servir.', kosher_type = 'Meat' where name = 'Roasted Veggies and Quinoa' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. Wash and dry the potatoes. Leave the peels on, cut each potato in half, and place in a baking pan. | Sprinkle the potatoes with the oil and bake, covered, until cooked through, about 1 hour. | In a large bowl, combine the baked potatoes with mayonnaise, mustard, garlic, lemon juice, Worcestershire sauce, gherkins, and dill. | Season with salt and black pepper. Serve warm, at room temperature, or cold. | Notes | Serves 4 to 6.', instructions_es = 'Precalienta el horno a 350°F. Lava y seca las papas. Déjalas con cáscara, corta cada una por la mitad y colócalas en una fuente para horno. | Rocía las papas con el aceite y hornéalas tapadas hasta que estén bien cocidas, aproximadamente 1 hora. | En un bowl grande, mezcla las papas cocidas con la mayonesa, la mostaza, el ajo, el jugo de limón, la salsa Worcestershire, los pepinillos y el eneldo. | Ajusta con sal y pimienta negra. Sirve tibia, a temperatura ambiente o fría.', kosher_type = 'Parve' where name = 'Baby Red Potato Salad with Caesar Dill Dressing' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Toast sesame seeds in a small frying pan over medium heat, stirring frequently, until golden and fragrant, about 10 minutes. | Place toasted sesame seeds in a food processor with the knife attachment. Add peanut butter, garlic, ginger, soy sauce, rice vinegar, hot sauce, and sugar. Blend, adding boiling water 1 tablespoon at a time until creamy. | Heat oven to grill. Broil chicken cutlets a few minutes on each side until lightly browned. Cool slightly and shred or cut into bite-size pieces. | In a large bowl, toss cooked spaghetti with sesame oil until evenly coated. Add shredded chicken, scallions, carrots, and sauce. Mix well. | Serve warm or at room temperature. | Notes | The note on the page says this side dish can be made without the cutlets and is just as delicious.', instructions_es = 'Tuesta las semillas de sésamo en una sartén pequeña a fuego medio, revolviendo seguido, hasta que estén doradas y aromáticas, unos 10 minutos. | Coloca las semillas tostadas en un procesador con cuchilla. Agrega la mantequilla de maní, el ajo, el jengibre, la salsa de soja, el vinagre de arroz, la salsa picante y el azúcar. Licúa, agregando agua hirviendo de a 1 cucharada hasta que quede cremoso. | Calienta el horno en función grill. Cocina los cutlets unos minutos por lado hasta que estén apenas dorados. Deja enfriar un poco y desmenúzalos o córtalos en trozos pequeños. | En un bowl grande, mezcla el spaghetti cocido con el aceite de sésamo hasta cubrirlo bien. Agrega el pollo, los cebollines, la zanahoria y la salsa. Mezcla bien. | Sirve tibio o a temperatura ambiente.', kosher_type = 'Dairy' where name = 'Sesame Noodles with Asian Dressing' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F and grease a 12-cup muffin tin. | Heat olive oil in a skillet over medium-high heat. | Sauté the onion until softened, about 3–5 minutes. | Add the garlic and cook 1 minute more. | Add the spinach and cook until wilted, then cool slightly. | Whisk the eggs with salt and pepper. | If using feta, divide it among the muffin cups. | Whisk the cooled onion mixture and herbs into the eggs. | Divide among the muffin cups. | Bake for 25–30 minutes, until set in the center.', instructions_es = '', kosher_type = 'Dairy' where name = 'Mini Spinach Frittatas' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix all ingredients together until combined. | Portion into muffin tins. | Bake until done. | Recipe Notes | The handwritten photo showed ingredients only. The baking time and temperature were not visible. | “Salt” was listed without a measured amount.', instructions_es = '', kosher_type = 'Parve' where name = 'Carrot Muffins' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Cook the lokshen. | In a bowl, combine the eggs, sugar, oil, vanilla sugar, and fruit cocktail. | Use a hand blender to mix the whole mixture. | Pour the mixture over the lokshen. | Bake at 350°F for at least 40 minutes. | Keep checking until the top is golden brown. | Recipe Notes | The original message did not specify the quantity of lokshen or the size of the fruit cocktail can/container.', instructions_es = '', kosher_type = 'Parve' where name = 'Lockshen Kugel' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Using the food processor with the “S” blade, blend the onions until very mushy. | Change to the “E” blade. | In a bowl, combine the eggs and oil, then add the potatoes and salt. | Preheat the oven to 350°F. | Grease the pan with Pam and place it in the oven for a few minutes. | Put the mixture into the pan. | Bake uncovered for 2 hours, until browned. | Let cool completely, then freeze. | Recipe Notes | The back of the note says: “To overnight, cover twice with water on the bottom, on 200°.” | The note appears to say “4 onions” in the food processor direction, but the ingredient list shows 1 medium onion. I kept the ingredient list exactly as written and noted the discrepancy here.', instructions_es = '', kosher_type = 'Parve' where name = 'Avis Kugel' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Blend all ingredients together. | Store in a closed container in the fridge.', instructions_es = 'Licúa o mezcla todos los ingredientes juntos. | Guarda en un recipiente cerrado en el refrigerador.', kosher_type = 'Parve' where name = 'Dill Dip' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Heat oil in a medium skillet over medium-high heat. Add shallots and sugar; sauté until brown, crispy, and somewhat caramelized. | Place into a container; add mayonnaise and salt. Blend well with an immersion blender until smooth and light brown.', instructions_es = 'Calienta el aceite en una sartén mediana a fuego medio-alto. Agrega las chalotas y el azúcar; saltea hasta que estén doradas, crujientes y algo caramelizadas. | Pásalas a un recipiente, agrega la mayonesa y la sal. Procesa bien con una batidora de inmersión hasta que quede suave y de color marrón claro.', kosher_type = 'Parve' where name = 'Shallot Dip' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place jalapeños over an open fire and roast for 5–10 minutes, until blistered and soft. Place in a plastic bag to sweat so they peel easily. Let cool and peel, removing stem. | In a food processor, blend pepper and mayonnaise. For less heat, remove some or all of the seeds first, then add back little by little to control the heat level. | Note | The screenshot also notes: if using store-bought mayonnaise, add 1 garlic clove and some salt and pepper when blending with the jalapeño.', instructions_es = 'Coloca los jalapeños sobre fuego directo y ásalos durante 5 a 10 minutos, hasta que estén ampollados y blandos. Pásalos a una bolsa plástica para que suden y así se puedan pelar con facilidad. Deja enfriar, pélalos y retira el tallo. | En un procesador de alimentos, licúa los jalapeños con la mayonesa. Si quieres menos picante, retira parte o todas las semillas antes y luego vuelve a añadirlas poco a poco para controlar el nivel de picor. | Nota | La imagen también indicaba que, si usas mayonesa comprada, debes añadir 1 diente de ajo y un poco de sal y pimienta al licuar con el jalapeño.', kosher_type = 'Parve' where name = 'Jalapeño Dip' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = '', kosher_type = 'Parve' where name = 'Eggplant Dip — Partial' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 400°F. Slice about 1/8 inch from the top of the garlic bulbs. Drizzle with oil, season, wrap in foil, and roast for 40–45 minutes until soft. | Squeeze roasted garlic cloves into a bowl. | Combine lemon zest and juice, olives, parsley, cilantro, chili, fresh garlic, and cashews, and mix into a paste with the roasted garlic. | Mound the mixture in the center of a plate. | Drizzle olive oil around it, add soy sauce, and season the oil with sea salt and freshly cracked black pepper. | Serve with warm crusty bread.', instructions_es = 'Precalienta el horno a 400°F. Corta aproximadamente 1/8 de pulgada de la parte superior de las cabezas de ajo. Rocía con aceite, sazona, envuelve en papel aluminio y asa durante 40 a 45 minutos, hasta que estén blandas. | Exprime los dientes de ajo asados en un bowl. | Mezcla la ralladura y el jugo de limón, las aceitunas, el perejil, el cilantro, el chile, el ajo fresco y los anacardos hasta formar una pasta junto con el ajo asado. | Coloca la mezcla en el centro de un plato. | Rocía aceite de oliva alrededor, agrega la salsa de soja y sazona el aceite con sal marina y pimienta negra recién molida. | Sirve con pan crujiente tibio.', kosher_type = 'Meat' where name = 'Roasted Garlic Dipping Oil' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Blend the yogurt, sugar, eggs, and vanilla in a blender or mixer. | Add the salt and cornstarch and mix again. | Pour into the graham cracker crust. | Bake at 350°F for 30 minutes. The middle may be slightly jiggly, but it should look baked and browned. | Let cool at least 6 hours before serving so it can set. | Notes | Source note on printout: “It’s not really cheesecake technically. But it’s really really good and no one would know.”', instructions_es = 'Licúa o mezcla el yogur, el azúcar, los huevos y la vainilla. | Agrega la sal y la maicena y vuelve a mezclar. | Vierte la mezcla en la base de galleta. | Hornea a 350°F durante 30 minutos. El centro puede quedar un poco tembloroso, pero debe verse cocido y dorado. | Deja enfriar por lo menos 6 horas antes de servir para que tome consistencia. | Notas | Nota original en la receta: “Técnicamente no es realmente un cheesecake. Pero es realmente, realmente bueno y nadie lo notaría.”', kosher_type = 'Dairy' where name = 'Low Fat Cheesecake' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté the diced portobello mushrooms and onion until soft. | Add the mushroom-onion mixture, prepared pesto, and shredded cheese. | Drizzle the top with olive oil. | Bake until the cheese is melted. | Notes | This screenshot appears to show only the variation/filling portion of the recipe, not the full base dough method.', instructions_es = 'Saltea los portobellos y la cebolla hasta que estén tiernos. | Agrega la mezcla de hongos y cebolla, el pesto preparado y el queso rallado. | Rocía la parte superior con aceite de oliva. | Hornea hasta que el queso se derrita. | Notas | Esta imagen parece mostrar solo la variación o relleno de la receta, no el método completo de la masa base.', kosher_type = 'Dairy' where name = 'Monkey Bread – Pesto' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Add the pizza or marinara sauce, tomato chunks, and shredded cheese. | Bake until the cheese is melted. | Notes | This screenshot appears to show only the variation/topping portion of the recipe, not the full base dough method.', instructions_es = 'Agrega la salsa para pizza o marinara, los trozos de tomate y el queso rallado. | Hornea hasta que el queso se derrita. | Notas | Esta imagen parece mostrar solo la variación o cobertura de la receta, no el método completo de la masa base.', kosher_type = 'Dairy' where name = 'Monkey Bread – Tomato' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine the yeast, sugar, and warm water. Let sit until bubbly, about 45 minutes. | Add 4 cups flour and the oil; mix for about 10 seconds. | Add the salt and the remaining 6 cups flour. | Mix until doughy. | Let rise for 30 minutes. | Top with sauce and cheese and bake. | Notes | Written from a photographed recipe card and WhatsApp follow-up. One line appears to read “mix for 10 sec.”', instructions_es = 'Mezcla la levadura, el azúcar y el agua tibia. Deja reposar hasta que haga burbujas, unos 45 minutos. | Agrega 4 tazas de harina y el aceite; mezcla durante unos 10 segundos. | Añade la sal y las 6 tazas restantes de harina. | Mezcla hasta formar una masa. | Deja levar durante 30 minutos. | Cubre con salsa y queso y hornea. | Notas | Tomado de una tarjeta de receta fotografiada y de un seguimiento por WhatsApp. Una línea parece decir “mezclar por 10 seg.”', kosher_type = 'Dairy' where name = 'Pizza Dough' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Layer all salad ingredients in a bowl, or divide among individual plates. | Place all vinaigrette ingredients into a food processor fitted with the S blade. | Pulse until completely combined. | Pour the dressing over the salad and toss to combine. | Notes | The original post notes that the salad also works well without the salmon.', instructions_es = 'Coloca todos los ingredientes de la ensalada en un bowl o divídelos en platos individuales. | Pon todos los ingredientes de la vinagreta en un procesador de alimentos con cuchilla S. | Procesa hasta que quede bien integrado. | Vierte el aderezo sobre la ensalada y mezcla. | Notas | La receta original indica que también queda muy bien sin el salmón.', kosher_type = 'Dairy' where name = 'Grilled Salmon Salad with Red Wine and Walnut Vinaigrette' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat the broiler to high. | Combine the parmesan, butter, mayo, and scallions. | Place the fish in a lightly greased pan. | Squeeze the juice of 1 lemon over the fillets and sprinkle with black pepper. | Broil 6 inches from the heat for 10 minutes. | Remove from the oven and spread the cheese mixture over the fillets. | Broil 2 minutes more, or until lightly browned and bubbly. | Notes | Recipe card title reads: “A Recipe For Parmesan-Crusted Grouper (or Sea Bass).”', instructions_es = 'Precalienta el gratinador del horno a temperatura alta. | Mezcla el parmesano, la mantequilla, la mayonesa y los cebollines. | Coloca el pescado en una fuente ligeramente engrasada. | Exprime el jugo de 1 limón sobre los filetes y espolvorea pimienta negra. | Gratina a 6 pulgadas del calor durante 10 minutos. | Retira del horno y extiende la mezcla de queso sobre los filetes. | Gratina 2 minutos más, o hasta que quede ligeramente dorado y burbujeante. | Notas | El título de la tarjeta decía: “A Recipe For Parmesan-Crusted Grouper (or Sea Bass).”', kosher_type = 'Dairy' where name = 'Parmesan-Crusted Grouper (or Sea Bass)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. | Add the pasta in an even layer to a 9- x 13-inch baking pan. | Add the salt and sauce. | Fill the empty sauce jar with water, anywhere from 3/4 full to completely full, and add it to the pan. | Add most of the cheese and mix to combine. Add more cheese on top, or mix all of it in. | Cover and bake for 90 minutes. | For a crisp top, uncover and bake a little longer until browned and bubbly and the noodles crisp up a bit.', instructions_es = 'Precalienta el horno a 350°F. | Coloca la pasta en una capa uniforme en una fuente para horno de 9 x 13. | Agrega la sal y la salsa. | Llena el frasco vacío de salsa con agua, desde 3/4 hasta completo, y viértela en la fuente. | Agrega la mayor parte del queso y mezcla para integrar. Añade más queso por encima, o mezcla todo el queso dentro. | Cubre y hornea durante 90 minutos. | Si quieres una capa superior crujiente, destapa y hornea un poco más hasta que se dore y burbujee, y los fideos se pongan un poco crocantes.', kosher_type = 'Dairy' where name = 'No Pot Creamy Ziti' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix ingredients together and divide into muffin pans. | Bake at 350°F for 25 minutes. | Note | This recipe was typed from a handwritten card and a few details may be worth double-checking.', instructions_es = 'Mezcla todos los ingredientes y reparte la preparación en moldes para muffins. | Hornea a 350°F durante 25 minutos. | Nota | Esta receta se transcribió de una tarjeta escrita a mano, por lo que conviene verificar algunos detalles.', kosher_type = 'Parve' where name = 'Weight Watchers Muffins – Leah Zicherman' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix together the egg, confectioner''s sugar, and cocoa powder until fully combined. | Place ingredients in a microwave-safe mug. | Microwave for 1 minute.', instructions_es = 'Mezcla el huevo, el azúcar impalpable y el cacao en polvo hasta que quede bien integrado. | Coloca la mezcla en una taza apta para microondas. | Cocina en el microondas durante 1 minuto.', kosher_type = 'Parve' where name = 'Ooey Gooey Chocolate Cake' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Whisk together margarine, sugar, vanilla extract, and soy milk. | Add baking powder, flour, and blueberries. | Place ingredients in a microwave-safe mug. | Microwave for 1 minute.', instructions_es = 'Bate la margarina, el azúcar, la vainilla y la leche de soja. | Agrega el polvo de hornear, la harina y los arándanos. | Coloca la mezcla en una taza apta para microondas. | Cocina en el microondas durante 1 minuto.', kosher_type = 'Dairy' where name = 'Instant Blueberry Muffin' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 325°F. Line a 7- by 11-inch brownie pan with parchment paper and coat with nonstick cooking spray. | In the bowl of an electric stand mixer, combine the melted margarine, cocoa powder, oil, sugar, flour, eggs, and vanilla. Beat to combine. | Spread the mixture into the prepared pan. | Bake for 35–40 minutes. Remove the pan from the oven and place into the refrigerator to cool for 20 minutes or until cool enough to handle. | When the brownies are cool, run a knife around the edge of the pan. Flip the brownie out onto a piece of parchment paper on a hard work surface in one whole piece. | Using a 1 1/2-inch diameter round cookie cutter, cut circles from the center of the brownie, leaving the harder crust. Roll the circles between the palms of your hands to form into balls, and roll into coating of your choice. | Store in an airtight container.', instructions_es = 'Precalienta el horno a 325°F. Forra un molde de 7 x 11 pulgadas con papel pergamino y rocíalo con spray antiadherente. | En el bowl de una batidora, mezcla la margarina derretida, el cacao, el aceite, el azúcar, la harina, los huevos y la vainilla. Bate hasta integrar. | Extiende la mezcla en el molde preparado. | Hornea de 35 a 40 minutos. Retira del horno y lleva el molde a la heladera durante 20 minutos o hasta que se enfríe lo suficiente para manipularlo. | Cuando el brownie esté frío, pasa un cuchillo por el borde del molde. Desmóldalo entero sobre una hoja de papel pergamino en una superficie firme. | Con un cortador redondo de 1 1/2 pulgadas, corta círculos del centro del brownie, dejando la parte más dura de los bordes. Forma bolitas con las manos y pásalas por la cobertura que prefieras. | Guarda en un recipiente hermético.', kosher_type = 'Parve' where name = 'Brownie Bites' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Bake puff pastry squares in a preheated 400°F oven for about 8–10 minutes, until golden and puffed. | Whip the topping until stiff peaks form, then mix in the vanilla instant pudding powder. | Assemble as shown: puff pastry, vanilla cream, berries, and another piece of puff pastry. | Sprinkle with confectioners'' sugar. Add a mint leaf for garnish if desired.', instructions_es = 'Hornea los cuadrados de hojaldre en un horno precalentado a 400°F durante unos 8 a 10 minutos, hasta que estén dorados e inflados. | Bate la cobertura hasta que forme picos firmes y luego incorpora el pudín instantáneo de vainilla. | Arma como se muestra: hojaldre, crema de vainilla, frutos rojos y otra pieza de hojaldre. | Espolvorea azúcar impalpable. Si deseas, decora con una hoja de menta.', kosher_type = 'Parve' where name = 'Flaky Dough Berry Sandwiches' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix ingredients together. | Bake at 350°F for about 22–23 minutes.', instructions_es = 'Mezcla todos los ingredientes. | Hornea a 350°F durante aproximadamente 22 a 23 minutos.', kosher_type = 'Dairy' where name = 'Banana Muffins – Mindy' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Blend yogurt, sugar, eggs, and vanilla in a blender or mixer. Add salt and cornstarch and mix again. | Pour into graham cracker crust. | Bake at 350°F for 30 minutes. The middle may be slightly jiggly, but it should look baked and brown. | Let cool at least 6 hours before serving to allow it to set.', instructions_es = 'Licúa o mezcla el yogur, el azúcar, los huevos y la vainilla. Agrega la sal y la maicena y vuelve a mezclar. | Vierte la mezcla en la base de galleta. | Hornea a 350°F durante 30 minutos. El centro puede quedar un poco tembloroso, pero debe verse cocido y dorado. | Deja enfriar al menos 6 horas antes de servir para que se asiente.', kosher_type = 'Dairy' where name = 'Low Fat Cheesecake' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 400°F. Grease 12 standard muffin cups; set aside. | Mix whole wheat flour, oats, brown sugar, baking powder, baking soda, cinnamon, applesauce, egg, apple juice, and vanilla in a large bowl by hand until just combined. | Stir in chocolate chips. | Pour batter into prepared muffin cups, filling each about 3/4 full. | Bake 17–20 minutes until centers are firm and muffins are light brown. Do not overbake.', instructions_es = 'Precalienta el horno a 400°F. Engrasa 12 moldes estándar para muffins y reserva. | Mezcla a mano en un bowl grande la harina integral, la avena, el azúcar morena, el polvo de hornear, el bicarbonato, la canela, el puré de manzana, el huevo, el jugo de manzana y la vainilla, solo hasta integrar. | Agrega las chispas de chocolate. | Reparte la mezcla en los moldes preparados, llenando cada uno hasta aproximadamente 3/4 de su capacidad. | Hornea de 17 a 20 minutos, hasta que el centro esté firme y los muffins estén ligeramente dorados. No hornees de más.', kosher_type = 'Parve' where name = 'Wholesome Breakfast Muffin' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Remove ice cream from freezer to soften. | In a small pot, melt chocolate chips and peanut butter. Add dried cranberries and potato chips and stir until well coated. | Stir half the mixture into the ice cream and spoon into pie crust. | Drop remaining mixture over top of pie, spreading to cover as much of the ice cream as possible. | Freeze immediately. | Note | You can use store-bought vanilla fudge ice cream or homemade vanilla ice cream. If using homemade, drizzle some chocolate syrup in when stirring the razzle mixture into the ice cream.', instructions_es = 'Saca el helado del freezer para que se ablande. | En una cacerola pequeña, derrite las chispas de chocolate con la mantequilla de maní. Agrega los arándanos secos y las papas fritas y mezcla hasta que queden bien cubiertos. | Incorpora la mitad de esta mezcla al helado y colócala dentro de la base de tarta. | Distribuye el resto de la mezcla sobre la parte superior, cubriendo la mayor cantidad posible del helado. | Lleva al freezer de inmediato. | Nota | Puedes usar helado comprado de vainilla con fudge o helado casero de vainilla. Si usas casero, puedes agregar un poco de salsa de chocolate al mezclar el relleno crocante con el helado.', kosher_type = 'Dairy' where name = 'Chipper Razzle Ice Cream Pie' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Beat whites. | Add sugar, then yolks, then remaining ingredients except cocoa mixture. | Pour 3/4 of the batter into pan. | To the remaining batter, add 2 tablespoons cocoa and 2 tablespoons sugar. Mix and pour on top of cake. Do not marbleize. | Bake at 325°F for about 45–50 minutes.', instructions_es = 'Bate las claras. | Agrega el azúcar, luego las yemas y después el resto de los ingredientes, excepto la mezcla de cacao. | Vierte 3/4 de la preparación en el molde. | A la mezcla restante, agrega 2 cucharadas de cacao y 2 cucharadas de azúcar. Mezcla y vierte por encima del pastel. No lo mezcles para marmolar. | Hornea a 325°F durante unos 45 a 50 minutos.', kosher_type = 'Parve' where name = 'Marble Cake' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix with a fork. Mix sugars with oil. | Add baking soda and salt. Mix. | Add egg and vanilla. Mix. | Add flour. Mix. | Form into 2 logs on a cookie sheet, pat down, sprinkle with Maldon sea salt flakes if using, and bake at 350°F for 20–30 minutes. The post notes 25 minutes for a slightly chewy texture. | When it comes out of the oven, slice into sticks.', instructions_es = 'Mezcla con un tenedor. Mezcla los azúcares con el aceite. | Agrega el bicarbonato y la sal. Mezcla. | Agrega el huevo y la vainilla. Mezcla. | Agrega la harina. Mezcla. | Forma 2 troncos sobre una bandeja para horno, aplánalos un poco, espolvorea con sal Maldon si la usas y hornea a 350°F durante 20 a 30 minutos. La publicación sugiere 25 minutos para una textura apenas chiclosa. | Al salir del horno, córtalos en bastones.', kosher_type = 'Parve' where name = 'Chocolate Chip Sticks' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F (180°C). Line two 9x13-inch pans or one large roasting pan with parchment paper. | Beat eggs on high speed for 10 minutes, adding the sugar in slow intervals. Add the remaining sponge cake ingredients and beat for a few more seconds, just until incorporated. | Pour into lined pans and bake for 42–50 minutes or until the top springs back and a toothpick inserted comes out clean. Let cool. | Beat the whipping cream and add the remaining strawberry cream ingredients. | Meanwhile, macerate the strawberries by combining them with sugar and basil, if using, and lemon juice. Mix together. Let rest at room temperature for 20 minutes until the strawberries are juicy and the sugar has dissolved. | Use a glass or the lid of a jar to cut circles out of the cake, and place one cut circle at the bottom of each jar. Top with a few spoons of the macerated strawberries and top with some strawberry whip. Repeat so you have 2 or 3 layers. | Garnish with strawberries and lemon peel, or basil. | Note | For a shortcut, use store-bought sponge cake, cut into slices and then into round disks. | Make the cake and cream ahead. Macerate berries and assemble up to 6 hours before serving.', instructions_es = 'Precalienta el horno a 350°F (180°C). Forra dos moldes de 9 x 13 pulgadas o una fuente grande para horno con papel pergamino. | Bate los huevos a velocidad alta durante 10 minutos, agregando el azúcar de a poco. Añade el resto de los ingredientes del bizcochuelo y bate solo unos segundos más, hasta integrar. | Vierte en los moldes preparados y hornea de 42 a 50 minutos, o hasta que la superficie rebote ligeramente y un palillo salga limpio. Deja enfriar. | Bate la crema y agrega el resto de los ingredientes de la crema de fresa. | Mientras tanto, macera las fresas mezclándolas con el azúcar, la albahaca si la usas, y el jugo de limón. Deja reposar a temperatura ambiente durante 20 minutos hasta que suelten jugo y el azúcar se disuelva. | Con un vaso o la tapa de un frasco, corta círculos del bizcochuelo y coloca uno en el fondo de cada frasco. Agrega unas cucharadas de fresas maceradas y encima un poco de crema de fresa. Repite para formar 2 o 3 capas. | Decora con fresas, cáscara de limón o albahaca. | Nota | Para una versión más rápida, usa bizcochuelo comprado y córtalo en discos redondos. | Puedes preparar el bizcochuelo y la crema con anticipación. Macera las fresas y arma el postre hasta 6 horas antes de servir.', kosher_type = 'Parve' where name = 'Jar of Strawberry Heaven' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Blend until smooth. Add more sugar to taste, if desired.', instructions_es = '', kosher_type = 'Dairy' where name = 'Berry Green Smoothie' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix the salt into the cereal. | Spray a 9x13-inch pan with cooking spray. | In a large saucepan over low heat, melt 4 tablespoons butter. You can also melt the butter in the microwave if you do not want to turn on the stove. | Gently stir the marshmallow fluff into the butter and allow it to fully melt. Stir until the butter and marshmallows are blended. | Remove the pan from the heat and stir in the Rice Krispies, salt, and Fruity Pebbles until the cereal is completely coated with the melted marshmallows. | Add mini marshmallows if desired. | Spread the mixture into the prepared pan, press down firmly, and sprinkle with extra Fruity Pebbles. | Refrigerate for 1 hour to set, then cut into bars. | Recipe Notes | The original post suggests you can swap in other favorite cereals such as Cocoa Pebbles, Cap’n Crunch, or Froot Loops. | The original post also mentions you can add chocolate chips or other mix-ins if you want.', instructions_es = 'Mezcla la sal con el cereal. | Rocía un molde de 9 x 13 pulgadas con spray antiadherente. | En una cacerola grande a fuego bajo, derrite 4 cucharadas de mantequilla. También puedes derretirla en el microondas si no quieres encender la cocina. | Agrega suavemente el marshmallow fluff a la mantequilla y deja que se derrita por completo. Revuelve hasta que la mantequilla y los malvaviscos estén bien integrados. | Retira la cacerola del fuego e incorpora los Rice Krispies, la sal y los Fruity Pebbles hasta que el cereal quede completamente cubierto con la mezcla derretida. | Agrega mini malvaviscos si deseas. | Pasa la mezcla al molde preparado, presiónala bien y espolvorea con más Fruity Pebbles. | Refrigera durante 1 hora para que tome consistencia y luego corta en barras. | Notas de la receta | La receta original sugiere que puedes cambiar el cereal por otros favoritos, como Cocoa Pebbles, Cap’n Crunch o Froot Loops. | También menciona que puedes agregar chispas de chocolate u otros ingredientes mezclados si quieres.', kosher_type = 'Dairy' where name = 'Fruity Pebble Fluff Treats' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Tightly wrap the riced cauliflower in a clean dish towel and squeeze until the crumbs are dry. If the cauliflower is still cold from the freezer, let it sit out for 20 minutes and squeeze again. The cauliflower should be very dry or the crust will become soggy. | Place the dry crumbs into a bowl; add eggs, salt, and spices. Mix really well until a dough forms. | Preheat oven to 400°F. Line a baking pan with parchment paper. | Form a quarter cup of dough into a two- to three-inch round and place onto the prepared pan. Repeat with remaining dough. Bake for 15 minutes, until they start to brown. Remove pan from oven. | Meanwhile, prepare the meat topping by adding all topping ingredients to a large bowl and mixing well to combine. | Reduce oven temperature to 350°F. Spread a quarter cup of meat topping onto each baked round, pressing down so it sticks to the dough. Spread topping all the way to the edges as the meat shrinks while it cooks. Sprinkle a few pine nuts on each, if using. | Bake until the meat is cooked through and browned, approximately 30 minutes.', instructions_es = 'Envuelve bien la coliflor rallada en un paño de cocina limpio y exprímela hasta que quede bien seca. Si todavía está fría por el congelador, déjala reposar 20 minutos y vuelve a exprimir. Debe quedar muy seca para que la base no se humedezca. | Coloca la coliflor seca en un bowl y agrega los huevos, la sal y las especias. Mezcla muy bien hasta formar una masa. | Precalienta el horno a 400°F. Forra una bandeja con papel pergamino. | Forma porciones de 1/4 de taza de masa en discos de 2 a 3 pulgadas y colócalos en la bandeja preparada. Repite con el resto. Hornea 15 minutos, hasta que empiecen a dorarse. Retira del horno. | Mientras tanto, prepara la cobertura mezclando todos los ingredientes en un bowl grande hasta integrar bien. | Reduce la temperatura del horno a 350°F. Coloca 1/4 de taza de cobertura sobre cada disco horneado, presionando para que se adhiera. Extiende la cobertura hasta los bordes porque la carne se encoge al cocinarse. Espolvorea algunos piñones encima, si los usas. | Hornea hasta que la carne esté cocida y dorada, aproximadamente 30 minutos.', kosher_type = 'Parve' where name = 'Cauliflower Crust Lachmagine' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. | Slice off the top of the garlic head and drizzle with olive oil. Seal in a tin foil pouch and bake for 1 hour. Let cool and squeeze out roasted cloves. | Meanwhile, bring an 8-quart pot to a full boil. Add cauliflower and cook for 10 minutes. Strain well. | Place hot cauliflower in a blender and pulse. Once it is well broken down, add roasted garlic, nondairy butter, and salt. Keep pulsing until mixture is smooth and creamy. | Remove from blender, add chives, and serve.', instructions_es = 'Precalienta el horno a 350°F. | Corta la parte superior de la cabeza de ajo y rocíala con aceite de oliva. Ciérrala en un paquetito de aluminio y hornéala durante 1 hora. Deja enfriar y exprime los dientes asados. | Mientras tanto, lleva una olla grande a hervor. Agrega la coliflor y cocina durante 10 minutos. Escurre bien. | Coloca la coliflor caliente en una licuadora y pulsa varias veces. Cuando esté bien triturada, agrega el ajo asado, la mantequilla vegetal y la sal. Sigue procesando hasta que quede suave y cremosa. | Retira de la licuadora, agrega el cebollín y sirve.', kosher_type = 'Dairy' where name = 'Garlic and Chive Cauliflower Mash' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Toss cauliflower with oil, then toss with the defrosted cubes. | Spread on a large baking sheet. It should be spread out a bit. | Bake at 425°F (220°C) for 25 minutes.', instructions_es = 'Mezcla la coliflor con el aceite y luego con los cubos descongelados. | Distribúyela en una bandeja grande para horno. Debe quedar bien extendida. | Hornea a 425°F (220°C) durante 25 minutos.', kosher_type = 'Parve' where name = 'Roasted Cauliflower' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 400°F. | Slice eggplants diagonally and spread on a lined cookie sheet. | Sprinkle with salt; then rub about 1 teaspoon of spice rub on each slice. | Brush melted schmaltz or oil on each piece. | Roast for 30 minutes, until browned and crispy. | Note | The recipe text notes that rendered chicken or duck fat gives extra flavor, but oil can be used instead.', instructions_es = 'Precalienta el horno a 400°F. | Corta las berenjenas en diagonal y colócalas sobre una bandeja forrada. | Espolvorea con sal y luego frota aproximadamente 1 cucharadita de mezcla de especias sobre cada rodaja. | Pincela cada pieza con schmaltz derretido o aceite. | Asa durante 30 minutos, hasta que estén doradas y crujientes. | Nota | La receta indica que la grasa de pollo o pato derretida aporta más sabor, pero se puede usar aceite.', kosher_type = 'Parve' where name = 'Roasted Italian Eggplant' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Mix ingredients together and divide into muffin pans. | Bake at 350°F for 25 minutes. | Note | This was typed from a handwritten card, so a few details may be worth double-checking.', instructions_es = 'Mezcla todos los ingredientes y reparte la preparación en moldes para muffins. | Hornea a 350°F durante 25 minutos. | Nota | Esta receta fue transcrita de una tarjeta escrita a mano, así que algunos detalles podrían valer la pena revisarlos.', kosher_type = 'Parve' where name = 'Weight Watchers Muffins – Leah Zicherman' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place brisket into the slow cooker and cover with sliced onions. | In a small bowl, combine the coffee, brown sugar, paprika, salt, minced onions, and garlic powder. Sprinkle the spice mixture over the onions and brisket. | Pour the barbecue sauce over the top. | Add the water to the empty sauce bottle, close and shake to loosen any remaining sauce, then pour that into the slow cooker as well. | Cook on Low for 8 hours. | Using two forks, shred the meat by pulling in opposite directions. | Mix well with the sauce and serve over mashed potatoes. | Notes | If your family does not use prepared sauces, double the spice rub and leave out the barbecue sauce. The brisket can still be served shredded or sliced. | Original note: Works great for a Shabbos or Yom Tov main, too.', instructions_es = 'Coloca el brisket en la olla lenta y cúbrelo con las rodajas de cebolla. | En un tazón pequeño, mezcla el café, el azúcar morena, el pimentón, la sal, la cebolla deshidratada y el ajo en polvo. Espolvorea esta mezcla sobre la cebolla y el brisket. | Vierte la salsa barbacoa por encima. | Agrega el agua a la botella vacía de salsa, ciérrala y agítala para aprovechar lo que queda de salsa. Luego vierte esa mezcla también en la olla lenta. | Cocina en temperatura Baja durante 8 horas. | Con dos tenedores, deshebra la carne tirando en direcciones opuestas. | Mézclala bien con la salsa y sírvela sobre puré de papas. | Notas | Si en tu casa no usan salsas preparadas, duplica la mezcla de especias y omite la salsa BBQ. El brisket igualmente se puede servir deshebrado o en rebanadas. | Nota original: también funciona muy bien como plato principal de Shabbos o Yom Tov.', kosher_type = 'Meat' where name = 'Slow Cooker Pulled Beef' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Rinse the French roast and pat dry. Season well with salt, pepper, and paprika. | Place the sugar in a sauté or braising pot large enough to fit the meat and cover. Cook over low heat, stirring occasionally, until the sugar melts and turns into a caramel color. | Add the meat to the pan on top of the caramelized sugar. Using a fork or tongs, rotate and sear both sides of the meat twice. | When all surfaces of the meat are browned, lift the roast and place the onions underneath. Cover and cook over medium-low heat for 2½–3 hours. Keep the flame low enough so the meat does not burn, but high enough that the sauce still bubbles slightly. | Remove the meat from the pan. | As the onions cook, their liquid will mix with the sugar and create a sauce. | In a small bowl, combine the potato starch and cold water. Add to the sauce and cook until thickened. | Slice the meat and serve with the caramelized onion sauce. | Notes | To freeze and rewarm: slightly undercook the roast. Freeze the meat and sugar-onion sauce separately. Rewarm the sauce and add the potato starch slurry only at that point, then slice the meat and reheat with the sauce. | One source note mentioned that the potato starch can be skipped if you prefer a thinner sauce. | Compiled from the recipe images you provided. | Source version: Cook Kosher', instructions_es = 'Enjuaga el roast francés y sécalo bien. Condiméntalo generosamente con sal, pimienta y pimentón. | Coloca el azúcar en una olla para saltear o para brasear que sea lo suficientemente grande como para que entre la carne y puedas taparla. Cocina a fuego bajo, revolviendo de vez en cuando, hasta que el azúcar se derrita y tome color caramelo. | Agrega la carne a la olla, encima del azúcar caramelizado. Con un tenedor o pinza, gírala y dóralo dos veces por ambos lados. | Cuando toda la superficie de la carne esté dorada, levanta el roast y coloca las cebollas debajo. | Tapa y cocina a fuego medio-bajo durante 2 1/2 a 3 horas. | Mantén el fuego lo suficientemente bajo para que la carne no se queme, pero lo suficientemente alto para que la salsa siga burbujeando apenas. | Retira la carne de la olla. | Mientras las cebollas se cocinan, su líquido se mezclará con el azúcar y formará una salsa. | En un bowl pequeño, mezcla la fécula de papa con el agua fría. Agrégala a la salsa y cocina hasta que espese. | Corta la carne en rebanadas y sírvela con la salsa de cebolla caramelizada. | Notas | Para congelar y recalentar: cocina el roast apenas un poco menos. Congela la carne y la salsa de azúcar y cebolla por separado. Recalienta la salsa y agrega la mezcla de fécula de papa recién en ese momento. Luego corta la carne y recaliéntala con la salsa. | Una de las notas de la fuente decía que la fécula de papa puede omitirse si prefieres una salsa más fina.', kosher_type = 'Parve' where name = 'Caramelized French Roast (Cook Kosher)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Mix all ingredients together until the batter is smooth. | 2. Pour the batter into cupcake pans or lined muffin tins. | 3. Bake for 20 to 25 minutes. | Notes | • The oven temperature was not visible in the screenshot source.', instructions_es = 'Mezcla todos los ingredientes hasta que la mezcla quede suave. | Vierte la mezcla en moldes para cupcakes o pirotines dentro de un molde para muffins. | Hornea durante 20 a 25 minutos. | Nota | La temperatura del horno no se veía en la imagen original.', kosher_type = 'Parve' where name = 'Pesach Chocolate Cupcakes' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = 'Precalienta el horno a 375°F. | Unta dos fuentes grandes y poco profundas para horno con 1 cucharada de aceite de oliva. Coloca los tomates, pimientos, zucchini y berenjena en una sola capa, con el lado cortado hacia abajo. Distribuye el ajo y la cebolla alrededor de los vegetales y rocía con el aceite restante. Espolvorea con tomillo y orégano, y sazona con sal y pimienta al gusto. | Hornea sin tapar durante 30 a 35 minutos, o hasta que los vegetales estén blandos y dorados. Cuando se enfríen, retira la pulpa de la berenjena y quita la piel de los pimientos y de los tomates. Coloca los vegetales en un recipiente grande y usa una licuadora de inmersión para triturar la berenjena, pimientos, zucchini, tomates, ajo y cebolla hasta obtener una textura gruesa, como salsa, no completamente lisa. | En una olla, mezcla el puré grueso de vegetales con el caldo y cocina a fuego lento durante 20 a 30 minutos. | Agrega la leche no láctea y cocina hasta que esté bien caliente. Ajusta la sal y la pimienta al gusto. | Sirve caliente y decora con albahaca fresca en tiras.', kosher_type = 'Parve' where name = 'Roasted Mediterranean Vegetable Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine lettuce, mango, pistachios, tomatoes, dried cranberries, and onion in a large bowl. | Place dressing ingredients in a small jar and shake or blend to combine. | Toss dressing with salad and serve.', instructions_es = 'Combine la lechuga, el mango, los pistachos, los tomates, los arándanos rojos secos y la cebolla en un tazón grande. | Coloque los ingredientes del aderezo en un frasco pequeño y agite, o mézclelos, hasta integrarlos. | Mezcle el aderezo con la ensalada y sirva.', kosher_type = 'Parve' where name = 'Situm Hashas Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a 6-quart pot or Dutch oven, sauté the onions in oil for approximately 15 minutes, until just golden (not brown or crisp). | Add the skinned chicken to the pot (“skin side” down) and brown for a few minutes, until the edges appear cooked. | Add the grape juice and salt, to taste. Bring to a boil. | Lower the heat and mix gently so all pieces of chicken are sitting in the juice. This assures that all pieces will be evenly colored. | Cook for 1½–2 hours. | If using fillets, cook for much less time, approximately ½–¾ hour. Chicken will then have a dark tinge to it. | When serving, remove the chicken carefully from the pot, as it will be very soft and you don’t want it to fall apart. | Source image transcription from user-provided WhatsApp screenshot.', instructions_es = 'En una olla grande o una Dutch oven de 6 cuartos, saltea las cebollas en el aceite durante aproximadamente 15 minutos, hasta que estén apenas doradas, no marrones ni crocantes. | Agrega el pollo a la olla y dóralo unos minutos, hasta que los bordes se vean apenas cocidos. | Agrega el jugo de uva y la sal, al gusto. Lleva a hervor. | Baja el fuego y mezcla suavemente para que todas las piezas de pollo queden asentadas en el jugo. Esto ayuda a que todo el pollo tome color de manera pareja. | Cocina de 1 1/2 a 2 horas. | Si usas filetes, cocina bastante menos tiempo, aproximadamente de 1/2 a 3/4 de hora. El pollo quedará con un tono oscuro. | Al servir, retira el pollo con cuidado de la olla, ya que quedará muy tierno y no querrás que se desarme.', kosher_type = 'Meat' where name = 'Succulent Chicken' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Combine mayonnaise, lemon juice, salt, and sugar until smooth. | Use immediately or refrigerate until needed.', instructions_es = 'Mezcle bien los huevos en un procesador de alimentos con la cuchilla en S; luego agregue el jugo de limón, la sal y el azúcar. | Agregue las 2 tazas de aceite y siga procesando hasta que el aderezo alcance la consistencia deseada. | Refrigere en un recipiente hermético. | CONSEJOS PARA ENSALADAS DE PÉSAJ | Toda ensalada puede comenzar con lechuga romana fresca y bien lavada. Luego puede agregar vegetales crudos o vegetales asados. Una buena ensalada con vegetales asados es una excelente guarnición. | Use calabaza, zanahorias o batatas. También puede usar vegetales de raíz o pimientos, si los usa. Mezcle los vegetales en una bandeja para horno con un poco de aceite y sal. Áselos en un horno precalentado hasta que estén dorados. | Corte rábanos pequeños en rodajas muy finas y mézclelos con los vegetales asados. Sirva los vegetales sobre la lechuga romana y añada sus nueces favoritas para dar crocancia, como nueces. | Para un almuerzo saludable, ralle un poco de queso feta sobre los vegetales asados.', kosher_type = 'Parve' where name = 'Basic Salad Dressing' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Rinse the French roast and pat dry. Season well with salt, pepper, and paprika. | Place the sugar in a sauté or braising pot large enough to fit the meat and cover. Cook over low heat, stirring occasionally, until the sugar melts and turns into a caramel color. | Add the meat to the pan on top of the caramelized sugar. Using a fork or tongs, rotate and sear both sides of the meat twice. | When all surfaces of the meat are browned, lift the roast and place the onions underneath. Cover and cook over medium-low heat for 2½–3 hours. Keep the flame low enough so the meat does not burn, but high enough that the sauce still bubbles slightly. | Remove the meat from the pan. | As the onions cook, their liquid will mix with the sugar and create a sauce. | In a small bowl, combine the potato starch and cold water. Add to the sauce and cook until thickened. | Slice the meat and serve with the caramelized onion sauce. | Notes | To freeze and rewarm: slightly undercook the roast. Freeze the meat and sugar-onion sauce separately. Rewarm the sauce and add the potato starch slurry only at that point, then slice the meat and reheat with the sauce. | One source note mentioned that the potato starch can be skipped if you prefer a thinner sauce. | Compiled from the recipe images you provided. | Source version: Between Carpools', instructions_es = 'Enjuaga el roast francés y sécalo bien. Condiméntalo generosamente con sal, pimienta y pimentón. | Coloca el azúcar en una olla para saltear o para brasear que sea lo suficientemente grande como para que entre la carne y puedas taparla. Cocina a fuego bajo, revolviendo de vez en cuando, hasta que el azúcar se derrita y tome color caramelo. | Agrega la carne a la olla, encima del azúcar caramelizado. Con un tenedor o pinza, gírala y dóralo dos veces por ambos lados. | Cuando toda la superficie de la carne esté dorada, levanta el roast y coloca las cebollas debajo. | Tapa y cocina a fuego medio-bajo durante 2 1/2 a 3 horas. | Mantén el fuego lo suficientemente bajo para que la carne no se queme, pero lo suficientemente alto para que la salsa siga burbujeando apenas. | Retira la carne de la olla. | Mientras las cebollas se cocinan, su líquido se mezclará con el azúcar y formará una salsa. | En un bowl pequeño, mezcla la fécula de papa con el agua fría. Agrégala a la salsa y cocina hasta que espese. | Corta la carne en rebanadas y sírvela con la salsa de cebolla caramelizada. | Notas | Para congelar y recalentar: cocina el roast apenas un poco menos. Congela la carne y la salsa de azúcar y cebolla por separado. Recalienta la salsa y agrega la mezcla de fécula de papa recién en ese momento. Luego corta la carne y recaliéntala con la salsa. | Una de las notas de la fuente decía que la fécula de papa puede omitirse si prefieres una salsa más fina.', kosher_type = 'Parve' where name = 'Caramelized French Roast (Between Carpools)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a small dish, mix potato starch, ½ teaspoon salt, and ¼ teaspoon pepper. Lightly coat chicken in the potato starch mixture, shaking off any excess. The coating should be light, because excess will create a gummy texture. | Heat oil in a large skillet over medium-high heat. Add chicken and brown until golden, about 3 minutes per side. Remove chicken and set aside on a loosely covered plate. | Add wine, broth, and lemon juice to the same skillet, scraping bits off the bottom of the pan and making sure any remaining potato starch is dissolved. Cook over high heat for about 5 minutes until reduced slightly. | Season with remaining 1 teaspoon salt and ¼ teaspoon pepper. Lower heat to a simmer and return chicken to skillet. | Top chicken with lemon slices and cook gently for 5 minutes. | Arrange chicken on a serving platter. Serve warm with sauce and lemon slices. | Source image transcription from user-provided magazine photo.', instructions_es = 'En un plato pequeño, mezcla la fécula de papa con 1/2 cucharadita de sal y 1/4 cucharadita de pimienta. | Pasa el pollo ligeramente por la mezcla de fécula de papa, sacudiendo el exceso. La capa debe ser liviana para que no quede gomosa. | Calienta el aceite en una sartén grande a fuego medio-alto. Agrega el pollo y dóralo hasta que esté dorado, aproximadamente 3 minutos por lado. Retíralo y resérvalo en un plato apenas cubierto. | Agrega el vino, el caldo y el jugo de limón a la misma sartén, raspando el fondo para soltar los sabores y asegurándote de que cualquier resto de fécula se disuelva. | Cocina a fuego alto durante unos 5 minutos, hasta que el líquido se reduzca un poco. | Agrega la cucharadita restante de sal y la 1/4 cucharadita restante de pimienta. Baja el fuego a suave y vuelve a colocar el pollo en la sartén. | Cubre el pollo con las rodajas de limón y cocina suavemente durante 5 minutos. | Pasa el pollo a una fuente de servir y sírvelo caliente con la salsa y las rodajas de limón.', kosher_type = 'Meat' where name = 'Chicken Francese' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Mix all ingredients together until well combined. | 2. Pour the batter into a 9 x 13-inch pan. | 3. Bake at 350°F for about 1 hour. For a fudgier texture, bake a little under 1 hour and adjust to your preference. | 4. For a gooey topping, cover the cake while it is still hot.', instructions_es = 'Mezcla todos los ingredientes hasta que estén bien integrados. | Vierte la mezcla en una fuente de 9 x 13 pulgadas. | Hornea a 350°F durante aproximadamente 1 hora. | Si la quieres más fudgy, hornéala un poco menos de 1 hora y ajusta según tu gusto. | Para una cobertura más pegajosa, tapa la torta mientras todavía está caliente.', kosher_type = 'Parve' where name = 'Pesach Chocolate Cake' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '', instructions_es = 'Fríe las cebollas, los cebollines y el apio a fuego bajo. Agrega las zanahorias en rodajas. | Coloca el pollo con hueso, dentro de la red, en la olla. | Agrega agua, sal y las especias que quieras, y deja que hierva. | Cuando hierva, baja el fuego y cocina durante 50 minutos a 1 hora. | Retira el pollo y córtalo en trozos pequeños. | Vuelve a poner el pollo en la olla, agrega la calabaza y cocina 40 minutos más. | Listo. | Nota | Esta receta provino de un mensaje de WhatsApp y no incluía cantidades exactas para la mayoría de los ingredientes.', kosher_type = 'Parve' where name = 'Veg Chicken Soup' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Slice the cucumbers and let them sit for 1/2 hour. | Combine water, vinegar, sugar, salt, purple onion, and carrot, if using. | Add the cucumbers and chill before serving.', instructions_es = 'Corte los pepinos en rodajas y déjelos reposar durante 1/2 hora. | Combine el agua, el vinagre, el azúcar, la sal, la cebolla morada y la zanahoria, si la usa. | Agregue los pepinos y enfríe antes de servir.', kosher_type = 'Parve' where name = 'Cucumber Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Season the meat generously with salt, pepper, and the 5 cloves or cubes of garlic. | Heat oil in a Dutch oven or oven-safe pot and sear the roast and neck bones on all sides. Remove from the pot. | Add a little more oil if needed, then sauté the onion and minced garlic until caramelized in spots. | Add the tomato paste. Return the roast to the pot and deglaze with the red wine. Add the brown sugar, soy sauce, red wine vinegar (or substitute mixture), apple cider vinegar, honey, maple syrup, and black pepper. Season with additional salt and pepper if needed. | Bring the mixture to a boil, cover the pot, and bake at 300°F for 3–4 hours. | Turn the roast over and bake for 1 additional hour. | Compiled from the recipe images you provided.', instructions_es = 'Condimenta la carne generosamente con sal, pimienta y los 5 dientes o cubos de ajo. | Calienta aceite en una Dutch oven o una olla apta para horno y sella el roast y los neck bones por todos lados. Retíralos de la olla. | Agrega un poco más de aceite si hace falta y saltea la cebolla y el ajo picado hasta que estén caramelizados en algunas partes. | Agrega la pasta de tomate. | Vuelve a poner el roast en la olla y desglasa con el vino tinto. | Agrega el azúcar morena, la salsa de soja, el vinagre de vino tinto o la mezcla alternativa, el vinagre de manzana, la miel, el maple y la pimienta negra. | Agrega más sal y pimienta si hace falta. | Lleva la mezcla a hervor, tapa la olla y hornea a 300°F durante 3 a 4 horas. | Da vuelta el roast y hornea 1 hora más.', kosher_type = 'Parve' where name = 'French Roast' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Preheat the oven to 350°F. | 2. Mix all cake ingredients until combined. | 3. Pour the batter into a 9 x 13-inch pan and bake for 20 minutes. | 4. While the cake is baking, combine all crumb topping ingredients and mix until crumbs form. | 5. After the cake has baked for 20 minutes, sprinkle the crumb topping evenly over the top. | 6. Return to the oven and bake for about 35 minutes more, or until a toothpick inserted comes out dry. | Notes | • One Instagram version says the cake may need a little more bake time depending on your oven.', instructions_es = 'Precalienta el horno a 350°F. | Mezcla todos los ingredientes de la torta hasta que estén unidos. | Vierte la mezcla en una fuente de 9 x 13 pulgadas y hornéala durante 20 minutos. | Mientras la torta se hornea, mezcla todos los ingredientes de la cobertura hasta formar migas. | Después de los primeros 20 minutos de horno, espolvorea la cobertura de migas de manera uniforme sobre la torta. | Vuelve a llevar al horno y hornea unos 35 minutos más, o hasta que al insertar un palillo salga seco. | Nota | Una de las versiones indicaba que puede necesitar un poco más de tiempo de horno según el horno.', kosher_type = 'Parve' where name = 'Pesach Crumb Cake' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Preheat the oven to 350°F. Lightly grease a 9 x 13-inch pan. | 2. Using an electric mixer, cream the eggs, sugar, oil, and vanilla extract in a large mixing bowl until light in color, thickened, and creamy. Add the cocoa, coffee, and potato starch. | 3. In a small bowl, combine the baking soda and vinegar, then add it to the batter and mix well. | 4. Pour the batter into the prepared pan and bake for 40 minutes. Allow the cake to cool completely before glazing. | 5. When the cake is completely cool, combine the glaze ingredients in a large bowl and stir until thick enough to pour. Pour over the cake to cover.', instructions_es = 'Precalienta el horno a 350°F. Engrasa ligeramente una fuente de 9 x 13 pulgadas. | Con batidora eléctrica, bate los huevos, el azúcar, el aceite y el extracto de vainilla hasta que la mezcla se aclare, espese y quede cremosa. | Agrega la cocoa, el café y la fécula de papa. | En un bowl pequeño, mezcla el bicarbonato con el vinagre y agrégalo a la mezcla. Bate bien. | Vierte la mezcla en la fuente preparada y hornea durante 40 minutos. | Deja enfriar por completo antes de glasear. | Cuando la torta esté completamente fría, mezcla todos los ingredientes del glaseado hasta que quede con textura suficientemente espesa pero vertible. | Vierte el glaseado sobre la torta para cubrirla.', kosher_type = 'Parve' where name = 'Glazed Chocolate Cake' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a medium bowl, combine quinoa, cucumber, carrot, tomatoes, avocado, chickpeas, feta cheese, and scallions. | In a small bowl, whisk together oil, lemon juice, cumin, Italian seasoning, salt, pepper, and garlic. | Toss dressing with salad and serve. | Yield: 4 servings', instructions_es = 'En un tazón mediano, combine la quinoa, el pepino, la zanahoria, los tomates, el aguacate, los garbanzos, el queso feta y los cebollines. | En un tazón pequeño, bata el aceite, el jugo de limón, el comino, el condimento italiano, la sal, la pimienta y el ajo. | Mezcle el aderezo con la ensalada y sirva. | Rinde: 4 porciones.', kosher_type = 'Dairy' where name = 'Mediterranean Quinoa Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Place the roast in a large roasting pan. | Drizzle with oil and season generously with kosher salt. Rub the seasoning into the meat. | For overnight roasting: roast uncovered overnight (at least 10 hours) at 190°F. | Alternative method: roast at 250°F for 7 hours. | Compiled from the recipe images you provided.', instructions_es = 'Coloca el roast en una fuente grande para horno. | Rocíalo con aceite y condiméntalo generosamente con sal kosher. | Frota bien la carne con el aceite y la sal. | Para cocción de toda la noche: ásalo destapado toda la noche, al menos 10 horas, a 190°F. | Método alternativo: ásalo a 250°F durante 7 horas.', kosher_type = 'Parve' where name = 'Slow Cooked French Roast' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Bring the water and sugar to a boil for the lemon layer. Add the lemon juice and turn off the flame. | 2. Place the lemon mixture in a 9 x 13-inch pan. Freeze, then blend until the mixture is slushy. | 3. For the watermelon layer, remove and discard about one-third of the watermelon rind. Cube the watermelon and blend with the confectionary sugar, lemon juice, and salt until smooth. | 4. Pour the watermelon mixture over the frozen lemon layer. | 5. Spoon the reserved lemon slush over the watermelon layer so it looks light and fluffy. Return to the freezer until firm. | 6. Let the ice stand briefly, then lightly scrape across the top to create a fine, snow-like texture. | Notes | • Some of the right-side text in the source image was cut off, so this recipe was reconstructed from the visible text.', instructions_es = 'Lleva a hervor el agua y el azúcar para la capa de limón. | Agrega el jugo de limón y apaga el fuego. | Coloca la mezcla de limón en una fuente de 9 x 13 pulgadas. Congélala y luego procésala o licúala hasta que quede tipo granizado. | Para la capa de sandía, retira y desecha aproximadamente un tercio de la cáscara. | Corta la sandía en cubos y licúala con el azúcar impalpable, el jugo de limón y la sal hasta que quede suave. | Vierte la mezcla de sandía sobre la capa de limón congelada. | Coloca encima el granizado de limón reservado para que quede con aspecto liviano y aireado. | Vuelve a llevar al freezer hasta que esté firme. | Antes de servir, déjalo reposar apenas y raspa suavemente la parte de arriba para crear una textura fina, como nieve. | Nota | Parte del texto del lado derecho estaba cortado en la imagen original, por lo que esta receta fue reconstruida a partir de lo visible.', kosher_type = 'Parve' where name = 'Fruitfreeze' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Pat the veal steaks dry and sprinkle generously with salt and pepper. | Sear over medium heat until golden brown. | Transfer to a disposable pan and generously cover the meat with duck sauce. | Bake for 1½ hours covered, then 15 minutes uncovered. | Notes | Homemade Duck Sauce: 2 segmented grapefruits, 2 segmented oranges, and ¾ cup sugar. Cook all ingredients for 45 minutes in a covered pot, then uncover and simmer for an additional 30 minutes. Let cool and blend to desired consistency. | Compiled from the recipe images you provided.', instructions_es = 'Seca bien los filetes de ternera y espolvoréalos generosamente con sal y pimienta. | Sella los filetes a fuego medio hasta que estén dorados. | Pásalos a una bandeja descartable y cúbrelos generosamente con salsa de pato. | Hornea 1 1/2 horas tapado y luego 15 minutos destapado. | Salsa de pato casera | 2 pomelos en gajos | 2 naranjas en gajos | 3/4 taza de azúcar | Preparación de la salsa de pato | Cocina todos los ingredientes durante 45 minutos en una olla tapada. | Luego destapa y cocina 30 minutos más a hervor suave. | Deja enfriar y licúa hasta llegar a la consistencia deseada.', kosher_type = 'Parve' where name = 'Sweetened Veal Steak' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Bring water to a boil and dip the tomatoes in for a few minutes. | Transfer tomatoes to cold water and peel them. | Pulse the tomatoes and onions in a food processor so the mixture is not too fine and not too chunky. | Season with salt, oil, and black pepper, tasting until it suits your preference.', instructions_es = 'Pruebe y ajuste el sabor hasta que quede a su gusto. | Un método es cocinar las remolachas con cáscara, pelarlas y molerlas. | Otro método es moler las remolachas crudas para obtener un sabor más parecido al comprado en tienda. | Mezcle con rábano picante y azúcar al gusto.', kosher_type = 'Meat' where name = 'Tomato Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Combine all crumb ingredients in a mixer or by hand and bake in a preheated 350°F (180°C) oven for about 20 minutes, or until browned nicely. | 2. Refrigerate well, then break the baked mixture into crumbs by hand. | 3. In a small pot, cook the chocolate, oil, coffee, and wine, stirring constantly until well combined. Cool slightly. | 4. Whip the egg yolks with 1/2 cup sugar for about 5 minutes. | 5. Reduce mixer speed and add the chocolate mixture. | 6. In a separate bowl, whip the egg whites with 1/4 cup sugar to make a firm foam. | 7. Fold the chocolate-egg yolk mixture into the egg whites until uniform. | 8. To assemble, pour some crumbs into the bottom of serving glasses. Pour chocolate mousse three-quarters of the way up. | 9. Cool the mousse and place a mound of whipped cream in the center, or add more crumbs on top. | 10. Keep refrigerated for up to 48 hours, or freeze for up to 2 weeks. | 11. For the chocolate squares, spread melted chocolate on parchment paper or a flat glass platter. Let dry at room temperature, cut into squares of different sizes, freeze for 10 minutes, then remove gently from the paper or glass. | 12. Decorate the mousse cups with the chocolate squares before serving.', instructions_es = 'Mezcla todos los ingredientes de las migas a mano o con batidora y hornéalos en horno precalentado a 350°F durante unos 20 minutos, o hasta que estén bien dorados. | Enfría bien y luego deshaz la mezcla horneada con la mano hasta formar migas. | En una ollita, cocina el chocolate, el aceite, el café y el vino, revolviendo constantemente hasta que todo quede bien integrado. Deja enfriar un poco. | Bate las yemas con 1/2 taza de azúcar durante aproximadamente 5 minutos. | Baja la velocidad de la batidora y agrega la mezcla de chocolate. | En otro bowl, bate las claras con 1/4 taza de azúcar hasta formar un merengue firme. | Incorpora la mezcla de chocolate y yemas dentro de las claras con movimientos envolventes hasta que quede uniforme. | Para armar, coloca un poco de migas en el fondo de cada copa o vaso. | Vierte la mousse de chocolate hasta llenar aproximadamente tres cuartos de cada copa. | Enfría la mousse y coloca en el centro un copete de topping batido, o agrega más migas por encima. | Guarda en la heladera hasta por 48 horas o congela hasta por 2 semanas. | Para hacer los cuadrados de chocolate, extiende el chocolate derretido sobre papel pergamino o una superficie plana de vidrio. | Déjalo secar a temperatura ambiente, córtalo en cuadrados de distintos tamaños y congélalo 10 minutos. | Retira con cuidado y usa para decorar las copas antes de servir.', kosher_type = 'Parve' where name = 'Chocolate Mousse Cups with Crispy Crumbs' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F. | Place pastrami in a roasting pan with water to cover. Cover tightly and place in the oven for 1 1/2 to 2 hours, until very soft. | When cool enough to handle, but still warm, shred the pastrami. Cover and set aside. | Place all dressing ingredients in a tall container and blend. | Combine the vegetables in a salad bowl. | Pour dressing over the salad vegetables and toss. Place shredded pastrami on top.', instructions_es = 'Hierva agua y sumerja los tomates durante unos minutos; luego páselos a agua fría. Pélelos. | Procese los tomates pelados y las cebollas en un procesador de alimentos. No los procese demasiado; deje la mezcla con algo de textura. | Sazone con sal, aceite y pimienta negra. | Pruebe y ajuste hasta que quede a su gusto.', kosher_type = 'Meat' where name = 'Shredded Pastrami Over Leafy Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Preheat oven to 350°F (175°C). | Combine apples, sugar, lemon juice, and cinnamon. Place in the bottom of a 9x13-inch baking pan or two 9-inch round pans. | Top with sliced strawberries. | With a fork, mix together the crumble ingredients. Crumble with your fingers and arrange on top of the strawberries. | Bake uncovered for 1 to 1 1/2 hours, or until done.', instructions_es = 'La imagen provista solo muestra los ingredientes de la cobertura y no incluye la base de manzana ni las instrucciones de horneado.', kosher_type = 'Parve' where name = 'Apple Strawberry Crumble' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = '1. Preheat the oven to 275°F. | 2. Beat the egg whites with the sugar until stiff peaks form. Add in the potato starch and vinegar. | 3. Line 2 baking sheets with parchment paper and trace a 9-inch round cake pan on the sheets to form 2 circles. Spoon meringue to fill the circles. | 4. Bake for 1 hour and 15 minutes. Shut off the heat and leave the meringues in the oven for 1 hour. | 5. In a blender or food processor, combine the canned pineapple, including the juices, with the potato starch. | 6. Transfer the pineapple mixture to a saucepan and bring to a boil over medium heat. Lower the heat and add the egg yolks and vanilla, whisking quickly so the eggs do not scramble. | 7. To assemble, spread pineapple curd over one meringue layer and top with fresh fruit. Repeat with the second layer, or assemble as individual desserts. | 8. Serve immediately after assembling.', instructions_es = 'Precalienta el horno a 275°F. | Bate las claras con el azúcar hasta formar picos firmes. | Agrega la fécula de papa y el vinagre. | Forra 2 bandejas con papel pergamino y marca 2 círculos usando un molde redondo de 9 pulgadas como guía. | Coloca el merengue dentro de los círculos. | Hornea durante 1 hora y 15 minutos. | Apaga el horno y deja los merengues dentro durante 1 hora más. | En licuadora o procesador, mezcla el ananá con su jugo junto con la fécula de papa. | Pasa la mezcla de ananá a una cacerola y llévala a hervor a fuego medio. | Baja el fuego y agrega las yemas y la vainilla, batiendo rápido para que las yemas no se cocinen en trozos. | Para armar, unta curd de ananá sobre una capa de merengue y cubre con fruta fresca. | Repite con la segunda capa o arma versiones individuales. | Sirve inmediatamente después de armar.', kosher_type = 'Parve' where name = 'Pineapple Curd Pavlova' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Blend all ingredients together in a food processor. | Use with roasted vegetables and greens.', instructions_es = '', kosher_type = 'Parve' where name = 'White Wine Dressing for Roasted Veggie Salad' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Sauté onions in oil for 7 to 8 minutes until clear and soft. | Add the flour or potato starch, stirring well. | Add the mayonnaise and chicken stock. Cook 2 to 3 minutes until the sauce thickens. Set aside. | Peel and slice the potatoes into 1/4-inch-thick slices. | Pour 3 to 4 ladles of sauce on the bottom of a 9x13-inch pan. | Spread a layer of potatoes, then sauce, then another layer of potatoes, ending with sauce on top. | Sprinkle with salt, pepper, and paprika. | Bake at 350°F for 1 to 1 1/2 hours, or until ready.', instructions_es = '', kosher_type = 'Meat' where name = 'Scalloped Potatoes - Pareve' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a medium saucepan over medium heat, sauté the onions and pastrami in the fat, stirring frequently, until the onions are caramelized and the pastrami is browned in spots. | Add potato starch and stir until the onion and pastrami mixture is evenly coated. | Add mayonnaise, chicken stock, salt, and pepper; stir until the mixture is smooth and thickened. | Preheat oven to 350°F. | Peel and slice potatoes crosswise into very thin circles. Rinse well with cold water. | Pour some sauce into a 9x13-inch baking dish. Arrange a layer of potato slices over the sauce, then more sauce, and continue the pattern until you have about 5 to 6 layers. Cover tightly with foil. | Bake for 30 minutes, then uncover and cook for another hour, or until crispy.', instructions_es = '', kosher_type = 'Meat' where name = 'Scalloped Potatoes with Pastrami' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'In a pot, sauté the onions with the margarine, brown sugar, and red wine vinegar until lightly golden. | Sprinkle the potato starch over the onions while stirring. | Add the water and soup mix and let it simmer until it thickens, then turn off the heat. Taste and add more salt if needed. | Slice the potatoes thinly. | Grease a baking dish or 9x13 pan and start layering sauce, potatoes, sauce, potatoes, ending with sauce on top. | Sprinkle with paprika and black pepper. | Bake at 350°F for about 1 1/2 hours.', instructions_es = '', kosher_type = 'Parve' where name = 'Scalloped Potatoes (Instagram Version)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'The provided image only shows the topping ingredients and does not include the rest of the recipe.', instructions_es = '', kosher_type = 'Parve' where name = 'Apple Kugel Topping (Partial)' and property_id = (select id from public.properties where name = 'Strauss' limit 1);
update public.recipes set instructions_en = 'Add the sugar and sliced onion to a pot and cook until the sugar melts. | Add the vinegar, lemon juice, additional sugar, salt, bay leaves or pickling spice, and water. | Bring to a low boil. | Add the fish and cook for 20-30 minutes, being careful not to overcook. | Serve cold. | Prepared from your uploaded recipe image', instructions_es = '', kosher_type = 'Parve' where name = 'Pesach Fish' and property_id = (select id from public.properties where name = 'Strauss' limit 1);